// ============================================
// n8n - Extraction JSON 
// ============================================

const item = $input.first();
const bin = item.binary?.attachment_0;

if (!bin) {
  throw new Error("Pièce jointe 'attachment_0' introuvable");
}

// Lecture du buffer
const buffer = await this.helpers.getBinaryDataBuffer(0, "attachment_0");

// Diagnostics (à désactiver en production)
const ENABLE_DIAGNOSTICS = false;
if (ENABLE_DIAGNOSTICS) {
  const head = buffer.subarray(0, 32);
  console.log("Binary info:", {
    fileName: bin.fileName,
    mimeType: bin.mimeType,
    size: bin.fileSize,
    hex: Buffer.from(head).toString('hex')
  });
}

// Détection compression
if (buffer[0] === 0x1f && buffer[1] === 0x8b) {
  throw new Error("Fichier GZIP détecté - décompression requise");
}
if (buffer[0] === 0x50 && buffer[1] === 0x4b) {
  throw new Error("Fichier ZIP détecté - extraction requise");
}

// Fonction de nettoyage unifiée
const cleanJson = (text) => {
  return text
    .replace(/^\uFEFF/, '') // BOM UTF-8
    .trim()
    .replace(/^[^[{]*/, '') // Supprimer avant [ ou {
    .replace(/[^\]}]*$/, ''); // Supprimer après ] ou }
};

// Tentatives de parsing (ordre d'encodages par fréquence)
const encodings = ['utf8', 'utf16le', 'latin1'];
let data = null;

for (const encoding of encodings) {
  try {
    const text = cleanJson(buffer.toString(encoding));
    if (text.startsWith('[') || text.startsWith('{')) {
      data = JSON.parse(text);
      break;
    }
  } catch (e) {
    continue; // Essayer l'encodage suivant
  }
}

if (!data) {
  throw new Error(
    `Parsing JSON impossible. Formats testés: ${encodings.join(', ')}\n` +
    `Aperçu: ${buffer.toString('utf8').slice(0, 100)}`
  );
}

// Normalisation et nettoyage
const items = Array.isArray(data) ? data : [data];
const cleaned = items.filter(item => {
  if (!item || typeof item !== 'object') return false;
  return Object.values(item).some(v => 
    v !== null && v !== undefined && v !== '' && String(v).trim() !== ''
  );
});

return cleaned.map(json => ({ json }));

// ============================================
// SPLIT EN BATCHES DE 20 ANNONCES
// ============================================

const allAnnonces = $input.all().map(item => item.json);
const BATCH_SIZE = 20;
const batches = [];

for (let i = 0; i < allAnnonces.length; i += BATCH_SIZE) {
  batches.push({
    json: {
      batchIndex: Math.floor(i / BATCH_SIZE),
      totalBatches: Math.ceil(allAnnonces.length / BATCH_SIZE),
      totalAnnonces: allAnnonces.length,
      annonces: allAnnonces.slice(i, i + BATCH_SIZE)
    }
  });
}

console.log(`📦 Créé ${batches.length} batches de ${BATCH_SIZE} annonces`);
return batches;

// ===============================
// HELPERS
// ===============================
const CURRENT_YEAR = 2026;

function extractFavoris(value) {
  if (!value) return 0;
  const m = String(value).match(/(\d+)\s*$/); // prend le dernier nombre
  return m ? parseInt(m[1], 10) : 0;
}
function extractCC(value) {
  if (!value) return "";

  const m = String(value).match(/(\d{2,4}(\.\d+)?)/);
  if (!m) return "";

  const cc = parseFloat(m[1]);

  // ❌ si inférieur à 49.8 → ne rien afficher
  if (cc < 49.8) return "";

  return cc;
}


function extractNbPhotos(value) {
  if (!value) return 0;

  const s = String(value);

  // ex: "Voir les 5 photos" / "Voir les photos" / "Voir 12 photos"
  const m = s.match(/(\d+)/);
  return m ? parseInt(m[1], 10) : 0;
}

/**
 * Parse matched_generations:
 * Exemples possibles:
 * - "SMCR (Gen2) 2021–2024"
 * - "SMCR (Gen2) 2021→"
 * - "(LC) 2018-2020"
 * - "2021→"
 */
function parseGenerations(value) {
  const s = String(value || "").trim();
  if (!s) return { label: "", yStart: "", yEnd: "" };

  // label = contenu entre parenthèses
  const labelMatch = s.match(/\(([^)]+)\)/);
  const label = labelMatch ? labelMatch[1].trim() : "";

  // Range "2002–2003" ou "2002-2003"
  const rangeMatch = s.match(/(\d{4})\s*[-–]\s*(\d{4})/);
  if (rangeMatch) {
    return { label, yStart: Number(rangeMatch[1]), yEnd: Number(rangeMatch[2]) };
  }

  // Arrow "2018→" => fin = année courante
  const arrowMatch = s.match(/(\d{4})\s*→/);
  if (arrowMatch) {
    return { label, yStart: Number(arrowMatch[1]), yEnd: CURRENT_YEAR };
  }

  // Fallback: une seule année
  const oneYear = s.match(/(\d{4})/);
  if (oneYear) {
    const y = Number(oneYear[1]);
    return { label, yStart: y, yEnd: y };
  }

  return { label: "", yStart: "", yEnd: "" };
}

// ===============================
// MAPPING
// ===============================
function mapField(item) {
  const gen = parseGenerations(item.matched_generations);

  return {
    json: {
      // ===============================
      // IDENTITÉ ANNONCE
      // ===============================
      Nom_annonce: item["text-headline-1-expanded"] || item.annonce_title || "",
      Url_Https: item["absolute href"] || item.annonce_url || "",

      // ✅ Favoris (chiffre uniquement)
      "personnes ont déjà ajouté cette annonce en favori": extractFavoris(item["u-shadow-border-transition"]),

"nombre de photos supplémentaires": extractNbPhotos(item["u-shadow-border-transition (2)"]),

      // ===============================
      // DATE / HEURE
      // ===============================
      "Date de mise en publication": item["text-caption"] || "",
      "Heure de mise en publication": item["text-caption (2)"] || "",

      // ===============================
      // PRIX
      // ===============================
      Prix_affiche: item["flex"] || item["text-headline-1"] || "",

      // ===============================
      // ✅ PHOTOS (3 clés récupérées)
      // ===============================
      Photo_1: item["size-full src"] || "",
      Photo_2: item["size-full src (2)"] || "",
      Photo_3: item["size-full src (3)"] || "",

          // ===============================
    // VEHICULE / VENDEUR (RENOMMÉ)
    // ===============================
    "nom du vendeur pro": item["text-body-1"] || "",

    "année du modèle": item["text-body-1 (4)"] || "",

    "Kilométrage": item["text-body-1 (5)"] || "",

    Mise_en_circulation: item["text-body-1 (6)"] || "",
Cylindree_cc: extractCC(item["text-body-1 (7)"]),

      // ===============================
      // ✅ DESCRIPTION COMPLÈTE
      // ===============================
"Description de l'annonce": item.annonce_description || "",

      // ===============================
      // STATUT / VENDEUR
      // ===============================
      Statut_annonce: item["box-border"] || "",

      // ✅ 3 clés récupérées côté vendeur
      Nom_vendeur: item["text-headline-1 (2)"] || "",
      "nombre d’avis": item["text-body-2"] || "",
      "Dernière activité": item["text-body-2 (2)"] || "",

      // (tu peux garder ces noms internes si tu en as encore besoin ailleurs)
      Paiement_ou_SIREN: item["text-body-2"] || "",
      Infos_vendeur: item["text-body-2 (2)"] || "",

      // ===============================
      // MATCHING
      // ===============================
      matched_marque: item.matched_marque || "",
      matched_modele: item.matched_modele || "",
      matched_generations: item.matched_generations || "",

      generation_label: gen.label || "",
      generation_year_start: gen.yStart || "",
      generation_year_end: gen.yEnd || "",

      matched_score: item.matched_score || "",
      matched_quality: item.matched_quality || "",
      needs_review: item.needs_review ?? false,
    }
  };
}

// ===============================
// RUN
// ===============================
return $input.all().map(i => mapField(i.json));

