// =====================================================
// MATCHING v9.1 VERROUILLÉ (ANTI-FAUX-POSITIFS) + COVERAGE BOOST (LBC 2026 KEYS)
// ✅ MAJ KEYS 2026 :
// - Brand: text-body-1 (2)
// - Title: text-body-1 (8) (version) puis text-headline-1-expanded puis relative
// - Desc: text-body-1 (16) (desc complète) puis text-body-1 (14)
// - Year: text-body-1 (4) puis text-body-1 (9)
// - CC SAFE: cubic_capacity via text-body-1 href (5) (le + fiable) > texte "xxx cc/cm3", ignore "xx km"
// - Model href: text-body-1 href (3) (page modèle)
// =====================================================

const allItems = $input.all().map(i => i.json);

// -------------------------
// GET robust
// -------------------------
const get = (obj, ...keys) => {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
};

const pick = (obj, keys) => {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
};

// -------------------------
// Champs annonces (✅ NEW KEYS 2026)
// -------------------------
const getAnnonceTitle = (a) =>
  get(a,
    "text-body-1 (8)",            // ✅ version / nom modèle détaillé (souvent très discriminant)
    "text-headline-1-expanded",   // fallback si présent
    "annonce_title",
    "relative"
  );

const getAnnonceDesc  = (a) =>
  get(a,
    "text-body-1 (16)",           // ✅ description complète (ton exemple)
    "text-body-1 (14)",           // fallback ancien mapping
    "description",
    "annonce_desc"
  );

const getAnnonceUrl   = (a) =>
  get(a,
    "absolute href",
    "annonce_url",
    "absolute href (1)",
    "absolute href (2)",
    "relative"
  );

// ✅ Brand: maintenant text-body-1 (2)
const getAnnonceBrand = (a) => get(a, "text-body-1 (2)", "annonce_brand_input");

// année brute: (4) puis (9)
const getAnnonceYearRaw1 = (a) => get(a, "text-body-1 (4)", "annonce_year_input_1");
const getAnnonceYearRaw2 = (a) => get(a, "text-body-1 (9)", "annonce_year_input_2");

// ✅ cc via filtre Leboncoin (le + fiable) : href(5) contient cubic_capacity:XXXX
const getAnnonceCCHref = (a) => get(a, "text-body-1 href (5)");

// ✅ modèle via href (3) (souvent u_moto_model:xxx)
const getAnnonceModelHref = (a) => get(a, "text-body-1 href (3)");

// -------------------------
// Champs modèles (référentiel)
// -------------------------
const getModeleField = (m) => pick(m, ["Modèle","Modele","modele","Model","MODELE","Modèle "]) || "";
const getMarqueField = (m) => pick(m, ["Marque","marque","MARQUE","Brand","brand"]) || "";
const getYearStartField = (m) => pick(m, ["Année début","Annee debut","Année début ","Year start","yearStart"]) || "";
const getYearEndField   = (m) => pick(m, ["Année fin","Annee fin","Année fin ","Year end","yearEnd"]) || "";

// -------------------------
// Normalisation + tokens
// -------------------------
const STOP = new Set([
  "moto","motos","scooter","roadster","trail","enduro","cross",
  "vend","vente","vends","urgent","etat","tres","super","parfait","excellent",
  "paiement","securise","option","full","abs","a2","ct","ok",
  "km","kms","kilometrage","kilometres","boite","vitesse","manuelle","automatique",
  "prix","euro","eur","garantie","factures","entretien","revision","controle"
]);

function normalize(text) {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  s = s.replace(/[/|]/g, " ");
  s = s.replace(/[^a-z0-9]+/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  s = s.replace(/\b(mt)\s*0?(\d{2})\b/g, "$1$2");
  s = s.replace(/\b(fz)\s*(\d)\b/g, "$1$2");
  s = s.replace(/\b(gs)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(dl)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(v\s*strom)\b/g, "vstrom");
  s = s.replace(/\b(v[-\s]?strom)\b/g, "vstrom");
  s = s.replace(/\b(x)\s*(max)\b/g, "xmax");

  return s;
}

const ALLOW_1LETTER = new Set(["r","x"]);

function splitAlphaNum(tok) {
  const parts = tok.match(/[a-z]+|\d+/g);
  return parts && parts.length > 1 ? parts : [];
}

function tokenizeModel(text) {
  const n = normalize(text);
  if (!n) return [];

  const raw = n.split(" ").filter(Boolean);
  const out = [];

  for (const t0 of raw) {
    const t = t0.trim();
    if (!t) continue;

    const parts = splitAlphaNum(t);
    if (parts.length) out.push(...parts);
    else out.push(t);
  }

  return out.filter(t => {
    if (!t) return false;
    if (STOP.has(t)) return false;
    if (/^\d+$/.test(t)) return true;
    if (t.length >= 2) return true;
    return ALLOW_1LETTER.has(t);
  });
}

function tokenize(text) {
  const n = normalize(text);
  if (!n) return [];

  const raw = n.split(" ").filter(Boolean);
  const out = [];

  for (const t0 of raw) {
    const t = t0.trim();
    if (!t) continue;

    out.push(t);
    const parts = splitAlphaNum(t);
    if (parts.length) out.push(...parts);
  }

  return out.filter(t => {
    if (!t) return false;
    if (STOP.has(t)) return false;
    if (/^\d+$/.test(t)) return true;
    return t.length >= 2;
  });
}

const tokensAlphaOnlyModel = (tokens) => tokens.filter(t => /[a-z]/.test(t));
const tokensAlphaOnly = (tokens) => tokens.filter(t => /[a-z]/.test(t));

// -------------------------
// Année (robuste)
// -------------------------
function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a, adText) {
  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const m = String(adText || "").match(/\b(19|20)\d{2}\b/);
  if (m) return parseInt(m[0], 10);

  return 0;
}

// -------------------------
// CC SAFE (anti "50 km")
// -------------------------
function ccFromHref(href) {
  const s = String(href || "");
  const m = s.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|cm 3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  return 0;
}

function getAnnonceCC(a, adText) {
  const ccH = ccFromHref(getAnnonceCCHref(a));   // ✅ href(5)
  if (ccH) return ccH;

  const ccT = extractCCFromText(adText);
  if (ccT) return ccT;

  return 0;
}

// -------------------------
// EXTRA: parse u_moto_model depuis href(3)
// ex: ...u_moto_model:V-STROM%20650...
// -------------------------
function isGenericModelLabel(modelStr) {
  const n = normalize(modelStr);
  return (
    n === "autre" ||
    n.endsWith(" autre") ||
    n.includes(" autre ") ||
    n.includes("_autre") ||
    n.includes(" other") ||
    n.includes("others") ||
    n.includes("unknown")
  );
}

function cleanModelFromHref2(modelStr, brandNorm) {
  if (!modelStr) return "";
  let s = String(modelStr).replace(/_/g, " ").trim();

  if (brandNorm) {
    const b = normalize(brandNorm);
    const sNorm = normalize(s);
    if (sNorm.startsWith(b + " ")) {
      s = s.slice(sNorm.indexOf(b) + b.length).trim();
    }
  }
  if (isGenericModelLabel(s)) return "";
  return s;
}

function decodePlus(s) {
  return String(s || "").replace(/\+/g, " ");
}
function extractModelFromHref2(href2) {
  const h = String(href2 || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try {
    return decodeURIComponent(decodePlus(m[1]));
  } catch (e) {
    return decodePlus(m[1]);
  }
}

// -------------------------
// Similarités
// -------------------------
function jaccard(aTokens, bTokens) {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}

function coverageSet(adSet, modelTokens) {
  if (!modelTokens.length) return 0;
  let hit = 0;
  for (const t of modelTokens) if (adSet.has(t)) hit++;
  return hit / modelTokens.length;
}

// -------------------------
// Dominant gate (A+B)
// -------------------------
const extractNumbers = (text) => {
  const s = normalize(text);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
};

function getModelDominantTokens(modelRaw) {
  const n = normalize(modelRaw);
  const nums = n.match(/\b\d{3,4}\b/g) || [];
  if (nums.length) return nums.map(Number);
  return tokenize(modelRaw).filter(t => /[a-z]/.test(t) && t.length >= 5);
}

// -------------------------
// Split modèles / annonces
// -------------------------
const modeles = [];
const annonces = [];

for (const item of allItems) {
  const isModel = !!getMarqueField(item) && !!getModeleField(item) &&
    (get(item, "Type (M/S/E)", "Type(M/S/E)", "Type (M\\/S\\/E)", "Cylindrée (cc)") !== "");

  const isAnnonce = get(item, "absolute href", "relative", "annonce_url") !== "";
  if (isModel) modeles.push(item);
  else if (isAnnonce) annonces.push(item);
}

if (!modeles.length) {
  return annonces.map(a => ({
    json: {
      ...a,
      matched_marque: "",
      matched_modele: "",
      matched_cylindree: "",
      matched_generations: "",
      matched_coloris: "",
      matched_annee_debut: "",
      matched_annee_fin: "",
      matching_engine: "NO_MODELS_INPUT",
      matched_score: 0,
      needs_review: true,
      reason_no_match: "no_models_input"
    }
  }));
}

// -------------------------
// Variantes modèle (alias "/")
// -------------------------
function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => normalize(p)).filter(Boolean);
  return Array.from(new Set(parts));
}

// -------------------------
// Index marques
// -------------------------
const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const brandNorm = normalize(brandRaw);
  const variants = modelVariants(modelRaw);

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;
  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const cc = Math.round(Number(get(m, "Cylindrée (cc)") || 0)) || 0;

  const variantAlphaTokens = variants
    .map(v => tokensAlphaOnlyModel(tokenizeModel(v)))
    .filter(t => t.length);

  if (!brandNorm || variantAlphaTokens.length === 0) continue;

  const dominants = getModelDominantTokens(modelRaw);

  const prepared = {
    raw: m,
    brandNorm,
    ys,
    ye,
    cc,
    variants,
    variantAlphaTokens,
    combinedTok: tokenize(`${brandRaw} ${modelRaw}`),
    dominants,
    modelNoSpace: normalize(modelRaw).replace(/\s+/g, "")
  };

  if (!brandIndex.has(brandNorm)) brandIndex.set(brandNorm, []);
  brandIndex.get(brandNorm).push(prepared);
}

const knownBrands = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// -------------------------
// Paramètres SAFE (verrouillés mais + coverage)
// -------------------------
const MIN_COV_ALPHA = 0.70;
const MIN_ACCEPT    = 0.78;
const FAST_COV      = 0.92;
const FAST_ACCEPT   = 0.72;
const CC_PENALTY    = 0.10;
const CC_BLOCK_DIFF = 250;

function computeScore(adTok, adSet, p) {
  let bestCov = 0;
  for (const vat of p.variantAlphaTokens) {
    const cov = coverageSet(adSet, vat);
    if (cov > bestCov) bestCov = cov;
  }
  const jac = jaccard(adTok, p.combinedTok);
  const score = (0.85 * bestCov) + (0.15 * jac);
  return { score, bestCov, jac };
}

// -------------------------
// MATCHING v9.1
// -------------------------
const results = [];

for (const a of annonces) {
  const title = getAnnonceTitle(a);
  const desc  = getAnnonceDesc(a);

  // ✅ champs utiles (MAJ indices 2026)
  const extraFields = [
    get(a, "text-body-1 (2)"),   // marque
    get(a, "text-body-1 (3)"),   // modèle (souvent vide)
    get(a, "text-body-1 (4)"),   // année
    get(a, "text-body-1 (5)"),   // km
    get(a, "text-body-1 (7)"),   // cc (souvent)
    get(a, "text-body-1 (8)"),   // version (très utile)
    get(a, "text-body-1 (9)"),   // mois/année
  ].filter(Boolean).join(" ");

  const url = getAnnonceUrl(a);

  const yearBlob = `${getAnnonceYearRaw1(a)} ${getAnnonceYearRaw2(a)}`.trim();
  const hrefCC = getAnnonceCCHref(a) || "";      // ✅ href(5)
  const hrefModel = getAnnonceModelHref(a) || ""; // ✅ href(3)
  const rawModelFromHref2 = extractModelFromHref2(hrefModel);

  const modelFromHref2 = rawModelFromHref2 || "";

  const adTextBase = `${title} ${desc} ${extraFields} ${yearBlob} ${hrefCC} ${modelFromHref2}`.trim();

  let brandAnnonce = normalize(getAnnonceBrand(a));
  const adNormBase = normalize(adTextBase);

  if (!brandAnnonce) {
    for (const b of knownBrands) {
      if (adNormBase.includes(b)) { brandAnnonce = b; break; }
    }
  }

  const modelFromHref2Clean = cleanModelFromHref2(modelFromHref2, brandAnnonce);

  const adTextUsed = modelFromHref2Clean
    ? `${adTextBase} ${modelFromHref2Clean}`.trim()
    : adTextBase;

  const adNorm    = normalize(adTextUsed);
  const adTok     = tokenize(adTextUsed);
  const adSet     = new Set(adTok);
  const adNumbers = extractNumbers(adTextUsed);

  const annonceYear = pickAnnonceYear(a, adTextUsed);
  const annonceCC   = getAnnonceCC(a, adTextUsed);

  if (!brandAnnonce || !brandIndex.has(brandAnnonce)) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,

        annonce_brand_input: getAnnonceBrand(a) || "",
        annonce_year_input_1: getAnnonceYearRaw1(a) || "",
        annonce_year_input_2: getAnnonceYearRaw2(a) || "",
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",

        matched_marque: "",
        matched_modele: "",
        matched_generations: "",
        matched_coloris: "",
        matched_annee_debut: "",
        matched_annee_fin: "",
        matched_cylindree: "",

        matched_score: 0,
        matching_engine: "NO_MATCH",
        needs_review: true,
        reason_no_match: "brand_not_found",

        _match_debug: {
          detectedBrand: brandAnnonce || null,
          adTextPreview: adTextUsed.slice(0, 250),
          modelFromHref2: modelFromHref2Clean || "",
          hrefModel: hrefModel || "",
          hrefCC: hrefCC || "",
          yearBlob,
          adNumbers,
          ccResolved: annonceCC || 0,
          yearResolved: annonceYear || 0,
          adTokensCount: adTok.length,
        }
      }
    });
    continue;
  }

  const baseCandidates = brandIndex.get(brandAnnonce);

  const passes = [{ useYear: true }, { useYear: false }];

  let bestPrepared = null;
  let bestRaw = null;
  let bestScore = 0;
  let bestCov = 0;
  let bestJac = 0;
  let usedYearFilter = false;
  let ccPenaltyApplied = false;

  let dominantGateRejectedCount = 0;
  let dominantGateBypassCount = 0;

  const adNoSpace = normalize(adTextUsed).replace(/\s+/g, "");

  for (const pass of passes) {
    let foundInPass = false;

    for (const p of baseCandidates) {
      if (pass.useYear && annonceYear) {
        if (annonceYear < p.ys || annonceYear > p.ye) continue;
      }

      const { score, bestCov: covA, jac } = computeScore(adTok, adSet, p);
      if (covA < MIN_COV_ALPHA) continue;

      const doms = p.dominants || [];
      const hasNumericDominant = doms.some(d => typeof d === "number");

      let dominantHit = false;
      for (const d of doms) {
        if (typeof d === "number") {
          if (adNumbers.includes(d)) { dominantHit = true; break; }
        } else {
          if (adSet.has(d)) { dominantHit = true; break; }
        }
      }

      const modelNoSpace = p.modelNoSpace || "";
      const strongBypass =
        (covA >= FAST_COV) ||
        (modelNoSpace && adNoSpace.includes(modelNoSpace));

      if (hasNumericDominant && !dominantHit) {
        dominantGateRejectedCount++;
        continue;
      }

      if (!hasNumericDominant && doms.length && !dominantHit && !strongBypass) {
        dominantGateRejectedCount++;
        continue;
      }

      if (!dominantHit && strongBypass) dominantGateBypassCount++;

      let penalty = 0;
      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);
        const strictBlock = (Math.min(p.cc, annonceCC) <= 600) ? 120 : CC_BLOCK_DIFF;

        if (diff >= strictBlock) continue;
        if (diff > 30) penalty = CC_PENALTY;
      }

      const finalScore = Math.max(0, score - penalty);

      if (finalScore > bestScore) {
        bestScore = finalScore;
        bestPrepared = p;
        bestRaw = p.raw;
        bestCov = covA;
        bestJac = jac;
        usedYearFilter = pass.useYear && !!annonceYear;
        ccPenaltyApplied = penalty > 0;
        foundInPass = true;
      }
    }

    if (pass.useYear && foundInPass) break;
  }

  const accept = !!bestPrepared && (bestScore >= MIN_ACCEPT || (bestCov >= FAST_COV && bestScore >= FAST_ACCEPT));

  results.push({
    json: {
      ...a,
      annonce_title: title,
      annonce_url: url,

      annonce_brand_input: getAnnonceBrand(a) || "",
      annonce_year_input_1: getAnnonceYearRaw1(a) || "",
      annonce_year_input_2: getAnnonceYearRaw2(a) || "",
      annonce_year_resolved: annonceYear || "",
      used_year_filter: usedYearFilter,

      annonce_cc_resolved: annonceCC || "",
      cc_source_href: ccFromHref(getAnnonceCCHref(a)) || "",

      matched_marque: accept ? (getMarqueField(bestRaw) || get(bestRaw, "Marque") || "") : "",
      matched_modele: accept ? (getModeleField(bestRaw) || get(bestRaw, "Modèle") || "") : "",
      matched_generations: accept ? (get(bestRaw, "Spéc/Génération") || get(bestRaw, "Spec/Generation") || "") : "",
      matched_coloris: accept ? (get(bestRaw, "Coloris commercial") || "") : "",
      matched_annee_debut: accept ? (get(bestRaw, "Année début") || getYearStartField(bestRaw) || "") : "",
      matched_annee_fin: accept ? (get(bestRaw, "Année fin") || getYearEndField(bestRaw) || "") : "",
      matched_cylindree: accept ? (get(bestRaw, "Cylindrée (cc)") || "") : "",

      matched_ok: !!accept,
      matched_quality: accept ? "match" : "no_match",
      needs_review: !accept,

      matched_score: accept ? Number(bestScore.toFixed(3)) : 0,
      matching_engine: accept ? "AUTO_V9_1_LOCKED_SAFE_LBC2026" : "NO_MATCH",
      reason_no_match: accept ? "" : "below_threshold_or_no_candidate_after_gates",

      _match_debug: {
        detectedBrand: brandAnnonce || null,
        adTextPreview: adTextUsed.slice(0, 250),
        modelFromHref2: modelFromHref2Clean || "",
        hrefModel: hrefModel || "",
        hrefCC: hrefCC || "",
        yearBlob,
        adNumbers,
        dominantGateRejectedCount,
        dominantGateBypassCount,
        bestModelDominants: accept ? (bestPrepared.dominants || []) : [],
        covAlphaBest: Number(bestCov.toFixed(3)),
        jacBest: Number(bestJac.toFixed(3)),
        minCovAlpha: MIN_COV_ALPHA,
        minAccept: MIN_ACCEPT,
        fastCov: FAST_COV,
        fastAccept: FAST_ACCEPT,
        ccPenaltyApplied,
        ccResolved: annonceCC || 0,
        adTokensCount: adTok.length,
      }
    }
  });
}

return results;

// ===============================
// HELPERS
// ===============================
const CURRENT_YEAR = 2026;

function extractFavoris(value) {
  if (!value) return 0;
  const m = String(value).match(/(\d+)\s*$/); // prend le dernier nombre
  return m ? parseInt(m[1], 10) : 0;
}
function extractCC(value) {
  if (!value) return "";

  const m = String(value).match(/(\d{2,4}(\.\d+)?)/);
  if (!m) return "";

  const cc = parseFloat(m[1]);

  // ❌ si inférieur à 49.8 → ne rien afficher
  if (cc < 49.8) return "";

  return cc;
}


function extractNbPhotos(value) {
  if (!value) return 0;

  const s = String(value);

  // ex: "Voir les 5 photos" / "Voir les photos" / "Voir 12 photos"
  const m = s.match(/(\d+)/);
  return m ? parseInt(m[1], 10) : 0;
}

/**
 * Parse matched_generations:
 * Exemples possibles:
 * - "SMCR (Gen2) 2021–2024"
 * - "SMCR (Gen2) 2021→"
 * - "(LC) 2018-2020"
 * - "2021→"
 */
function parseGenerations(value) {
  const s = String(value || "").trim();
  if (!s) return { label: "", yStart: "", yEnd: "" };

  // label = contenu entre parenthèses
  const labelMatch = s.match(/\(([^)]+)\)/);
  const label = labelMatch ? labelMatch[1].trim() : "";

  // Range "2002–2003" ou "2002-2003"
  const rangeMatch = s.match(/(\d{4})\s*[-–]\s*(\d{4})/);
  if (rangeMatch) {
    return { label, yStart: Number(rangeMatch[1]), yEnd: Number(rangeMatch[2]) };
  }

  // Arrow "2018→" => fin = année courante
  const arrowMatch = s.match(/(\d{4})\s*→/);
  if (arrowMatch) {
    return { label, yStart: Number(arrowMatch[1]), yEnd: CURRENT_YEAR };
  }

  // Fallback: une seule année
  const oneYear = s.match(/(\d{4})/);
  if (oneYear) {
    const y = Number(oneYear[1]);
    return { label, yStart: y, yEnd: y };
  }

  return { label: "", yStart: "", yEnd: "" };
}

// ===============================
// MAPPING
// ===============================
function mapField(item) {
  const gen = parseGenerations(item.matched_generations);

  return {
    json: {
      // ===============================
      // IDENTITÉ ANNONCE
      // ===============================
      Nom_annonce: item["text-headline-1-expanded"] || item.annonce_title || "",
      Url_Https: item["absolute href"] || item.annonce_url || "",

      // ✅ Favoris (chiffre uniquement)
      "personnes ont déjà ajouté cette annonce en favori": extractFavoris(item["u-shadow-border-transition"]),

"nombre de photos supplémentaires": extractNbPhotos(item["u-shadow-border-transition (2)"]),

      // ===============================
      // DATE / HEURE
      // ===============================
      "Date de mise en publication": item["text-caption"] || "",
      "Heure de mise en publication": item["text-caption (2)"] || "",

      // ===============================
      // PRIX
      // ===============================
      Prix_affiche: item["flex"] || item["text-headline-1"] || "",

      // ===============================
      // ✅ PHOTOS (3 clés récupérées)
      // ===============================
      Photo_1: item["size-full src"] || "",
      Photo_2: item["size-full src (2)"] || "",
      Photo_3: item["size-full src (3)"] || "",

          // ===============================
    // VEHICULE / VENDEUR (RENOMMÉ)
    // ===============================
    "nom du vendeur pro": item["text-body-1"] || "",

    "année du modèle": item["text-body-1 (4)"] || "",

    "Kilométrage": item["text-body-1 (5)"] || "",

    Mise_en_circulation: item["text-body-1 (6)"] || "",
Cylindree_cc: extractCC(item["text-body-1 (7)"]),

      // ===============================
      // ✅ DESCRIPTION COMPLÈTE
      // ===============================
"Description de l'annonce": item.annonce_description || "",

      // ===============================
      // STATUT / VENDEUR
      // ===============================
      Statut_annonce: item["box-border"] || "",

      // ✅ 3 clés récupérées côté vendeur
      Nom_vendeur: item["text-headline-1 (2)"] || "",
      "nombre d’avis": item["text-body-2"] || "",
      "Dernière activité": item["text-body-2 (2)"] || "",

      // (tu peux garder ces noms internes si tu en as encore besoin ailleurs)
      Paiement_ou_SIREN: item["text-body-2"] || "",
      Infos_vendeur: item["text-body-2 (2)"] || "",

      // ===============================
      // MATCHING
      // ===============================
      matched_marque: item.matched_marque || "",
      matched_modele: item.matched_modele || "",
      matched_generations: item.matched_generations || "",

      generation_label: gen.label || "",
      generation_year_start: gen.yStart || "",
      generation_year_end: gen.yEnd || "",

      matched_score: item.matched_score || "",
      matched_quality: item.matched_quality || "",
      needs_review: item.needs_review ?? false,
    }
  };
}

// ===============================
// RUN
// ===============================
return $input.all().map(i => mapField(i.json));

// ==============================================
// AUTO DETECTION MODELES vs ANNONCES (v10 - NEW KEYS LBC 2026)
// - Brand: priorité text-body-1 (2) (sinon détection dans texte)
// - Texte match: version text-body-1 (8) + description text-body-1 (16) + champs structurés
// - Année: text-body-1 (4) puis (9) => pass 1 strict, pass 2 sans année
// - CC: priorité champ dédié text-body-1 (7) / (13) puis href(5) cubic_capacity, sinon extraction SAFE
// ✅ ANTI-UPGRADE: inchangé (dominants + adNumbers)
// - Si insuffisant => match vide (plutôt que faux)
// ==============================================

const allItems = $input.all().map(i => i.json);

// ---------- GET robust ----------
const get = (obj, ...keys) => {
  for (const k of keys) {
    if (obj && obj[k] !== undefined && obj[k] !== null && String(obj[k]).trim() !== "") return obj[k];
  }
  return "";
};

// ---------- Champs annonces (✅ NEW KEYS) ----------
const getAnnonceTitle = (a) =>
  get(a,
    "text-body-1 (8)",              // ✅ version / vrai nom modèle (ex: 1050_Speed Triple 1050 ABS)
    "text-headline-1-expanded",     // fallback si jamais
    "relative"
  );

const getAnnonceDesc  = (a) =>
  get(a,
    "text-body-1 (16)",             // ✅ description complète (ton exemple)
    "text-body-1 (14)"              // fallback ancien mapping si présent
  );

const getAnnonceUrl   = (a) =>
  get(a,
    "absolute href",
    "absolute href (1)",
    "absolute href (2)",
    "absolute href (3)",
    "relative"
  );

// ✅ Brand now is text-body-1 (2)
const getAnnonceBrand = (a) => get(a, "text-body-1 (2)");

// ✅ Année: (4) puis fallback (9)
const getAnnonceYearRaw1 = (a) => get(a, "text-body-1 (4)"); // ex: 2013
const getAnnonceYearRaw2 = (a) => get(a, "text-body-1 (9)"); // ex: 11/2017

// ✅ CC dedicated fields
const getAnnonceCCField1 = (a) => get(a, "text-body-1 (7)");      // ex: "1050"
const getAnnonceCCField2 = (a) => get(a, "text-body-1 (13)");     // ex: "1050 cm³" (parfois vide)
const getAnnonceCCHref   = (a) => get(a, "text-body-1 href (5)");  // ex: ... cubic_capacity:1050 ...

// ---------- Champs modèles (référentiel) ----------
const pick = (obj, keys) => {
  for (const k of keys) {
    if (obj && obj[k] !== undefined && obj[k] !== null && String(obj[k]).trim() !== "") return obj[k];
  }
  return "";
};
const getModeleField    = (m) => pick(m, ["Modèle", "Modele", "modele", "Model", "MODELE", "Modèle "]);
const getMarqueField    = (m) => pick(m, ["Marque", "marque", "MARQUE", "Brand", "brand"]);
const getYearStartField = (m) => pick(m, ["Année début", "Annee debut", "Année début ", "Year start", "yearStart"]);
const getYearEndField   = (m) => pick(m, ["Année fin", "Annee fin", "Année fin ", "Year end", "yearEnd"]);

// ---------- Normalisation + alias ----------
const normalize = (text) => {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  s = s.replace(/[/|]/g, " ");
  s = s.replace(/[^a-z0-9]+/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  s = s.replace(/\bevolution\b/g, "evo");
  s = s.replace(/\bmonster evolution\b/g, "monster evo");

  s = s.replace(/\b(mt)\s*0?(\d{2})\b/g, "$1$2");
  s = s.replace(/\b(fz)\s*(\d)\b/g, "$1$2");
  s = s.replace(/\b(x)\s*(cape)\b/g, "$1$2");

  return s;
};

const tokenize = (text) => {
  const n = normalize(text);
  return n ? n.split(" ").filter(Boolean) : [];
};

const isAlphaToken = (t) => /[a-z]/.test(t);
const tokensAlphaOnly = (tokens) => tokens.filter(t => isAlphaToken(t));

// ---------- Similarité ----------
const jaccard = (aTokens, bTokens) => {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
};

const coverageSet = (adSet, modelTokens) => {
  if (!modelTokens.length) return 0;
  let hit = 0;
  for (const t of modelTokens) if (adSet.has(t)) hit++;
  return hit / modelTokens.length;
};

// ---------- Parsing année annonce ----------
function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a) {
  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  return 0;
}

// ---------- CC extraction SAFE (ignore "xx km") ----------
function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|cm 3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  return 0; // pas de guess via nombre isolé
}

function extractCCFromField(value) {
  const m = String(value || "").match(/(\d{2,4})/);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromHref(href) {
  const h = String(href || "");
  const m = h.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function getAnnonceCC(a) {
  // ✅ priorité aux champs dédiés
  const cc1 = extractCCFromField(getAnnonceCCField1(a));
  if (cc1) return cc1;

  const cc2 = extractCCFromText(getAnnonceCCField2(a));
  if (cc2) return cc2;

  const cch = extractCCFromHref(getAnnonceCCHref(a));
  if (cch) return cch;

  // fallback SAFE: version/titre/desc
  const ccTitle = extractCCFromText(getAnnonceTitle(a));
  if (ccTitle) return ccTitle;

  const ccDesc = extractCCFromText(getAnnonceDesc(a));
  if (ccDesc) return ccDesc;

  return 0;
}

// ---------- ANTI-UPGRADE: nombres structurels & tokens dominants ----------
const extractNumbers = (text) => {
  const raw = String(text || "")
    .replace(/\b(\d{1,6})\s*km\b/gi, " ")
    .replace(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/g, " ");
  const s = normalize(raw);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
};

function getModelDominantTokens(modelRaw) {
  const n = normalize(modelRaw);
  const nums = n.match(/\b\d{3,4}\b/g) || [];
  if (nums.length) return Array.from(new Set(nums.map(Number)));

  const toks = tokenize(modelRaw);
  const dominants = toks.filter(t => /\d/.test(t) || t.length >= 5);
  return Array.from(new Set(dominants));
}

// ---------- 1) Séparer modèles / annonces ----------
const modeles = [];
const annonces = [];

for (const item of allItems) {
  const isModel =
    getMarqueField(item) &&
    getModeleField(item) &&
    (get(item, "Type (M/S/E)", "Type(M/S/E)", "Type (M\\/S\\/E)") !== "");

  if (isModel) modeles.push(item);
  else annonces.push(item);
}

// ---------- 2) Préparer modèles + alias ----------
function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => normalize(p)).filter(Boolean);
  if (!parts.length) return [];
  return Array.from(new Set(parts));
}

// ---------- Index marques ----------
const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const brandNorm = normalize(brandRaw);
  const variants = modelVariants(modelRaw);

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;
  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const cc = Math.round(Number(get(m, "Cylindrée (cc)") || 0)) || 0;

  const variantAlphaTokens = variants.map(v => tokensAlphaOnly(tokenize(v))).filter(t => t.length);
  if (!brandNorm || variantAlphaTokens.length === 0) continue;

  const dominants = getModelDominantTokens(modelRaw);

  const prepared = {
    raw: m,
    brandNorm,
    ys,
    ye,
    cc,
    variants,
    variantAlphaTokens,
    combinedTok: tokenize(`${brandRaw} ${modelRaw}`),
    dominants
  };

  if (!brandIndex.has(brandNorm)) brandIndex.set(brandNorm, []);
  brandIndex.get(brandNorm).push(prepared);
}

const knownBrands = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// ---------- Paramètres SAFE ----------
const MIN_COV_ALPHA = 0.85;
const MIN_ACCEPT    = 0.78;
const CC_BLOCK_DIFF = 250;
const CC_PENALTY_SCORE = 0.12;

function computeScore(adTok, adSet, p) {
  let bestCov = 0;
  for (const vat of p.variantAlphaTokens) {
    const cov = coverageSet(adSet, vat);
    if (cov > bestCov) bestCov = cov;
  }
  const jac = jaccard(adTok, p.combinedTok);
  const score = (0.85 * bestCov) + (0.15 * jac);
  return { score, bestCov, jac };
}

// ---------- Matching ----------
const results = [];

for (const a of annonces) {
  const title = getAnnonceTitle(a);
  const desc  = getAnnonceDesc(a);
  const url   = getAnnonceUrl(a);

  // ✅ enrichir le texte avec les champs structurés (brand/cc/model éventuel)
  const brandField = getAnnonceBrand(a);
  const ccField = getAnnonceCCField1(a) || getAnnonceCCField2(a) || "";
  const modelField = get(a, "text-body-1 (3)"); // si parfois présent
  const adText = `${title} ${brandField} ${modelField} ${ccField} ${desc}`.trim();

  const adNorm = normalize(adText);
  const adTok  = tokenize(adText);
  const adSet  = new Set(adTok);

  // marque: priorité text-body-1 (2), sinon détection dans texte
  let brandAnnonce = normalize(brandField);
  if (!brandAnnonce) {
    for (const b of knownBrands) {
      if (adNorm.includes(b)) { brandAnnonce = b; break; }
    }
  }

  const annonceYear = pickAnnonceYear(a);
  const annonceCC   = getAnnonceCC(a);

  const adNumbers = extractNumbers(adText);

  if (!brandAnnonce || !brandIndex.has(brandAnnonce)) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_brand_input: brandField || "",
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",
        matched_marque: "",
        matched_modele: "",
        matched_generations: "",
        matched_coloris: "",
        matched_annee_debut: "",
        matched_annee_fin: "",
        matched_cylindree: "",
        matched_score: 0,
        matching_engine: "NO_MATCH",
        needs_review: true,
        reason_no_match: "brand_not_found",
        _match_debug: { detectedBrand: brandAnnonce || null, adNumbers }
      }
    });
    continue;
  }

  const baseCandidates = brandIndex.get(brandAnnonce);

  const passes = [{ useYear: true }, { useYear: false }];

  let bestPrepared = null;
  let bestScore = 0;
  let bestCov = 0;
  let bestJac = 0;
  let usedYearFilter = false;
  let ccPenaltyApplied = false;
  let dominantGateRejectedCount = 0;

  for (const pass of passes) {
    let foundInPass = false;

    for (const p of baseCandidates) {
      if (pass.useYear && annonceYear) {
        if (annonceYear < p.ys || annonceYear > p.ye) continue;
      }

      // ✅ ANTI-UPGRADE: dominant obligatoire
      let dominantHit = false;
      if (p.dominants && p.dominants.length) {
        for (const d of p.dominants) {
          if (typeof d === "number") {
            if (adNumbers.includes(d)) { dominantHit = true; break; }
          } else {
            if (adSet.has(d)) { dominantHit = true; break; }
          }
        }
        if (!dominantHit) { dominantGateRejectedCount++; continue; }
      }

      const { score, bestCov: covA, jac } = computeScore(adTok, adSet, p);

      if (covA < MIN_COV_ALPHA) continue;

      let finalScore = score;
      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);
        if (diff >= CC_BLOCK_DIFF) continue;
        if (diff > 30) { finalScore -= CC_PENALTY_SCORE; ccPenaltyApplied = true; }
        if (finalScore < 0) finalScore = 0;
      }

      if (finalScore > bestScore) {
        bestScore = finalScore;
        bestPrepared = p;
        bestCov = covA;
        bestJac = jac;
        usedYearFilter = pass.useYear && !!annonceYear;
        foundInPass = true;
      }
    }

    if (pass.useYear && foundInPass) break;
  }

  const accept = bestPrepared && bestScore >= MIN_ACCEPT;
  const best = accept ? bestPrepared.raw : null;

  results.push({
    json: {
      ...a,

      annonce_title: title,
      annonce_url: url,

      annonce_brand_input: brandField || "",
      annonce_year_input_1: getAnnonceYearRaw1(a) || "",
      annonce_year_input_2: getAnnonceYearRaw2(a) || "",
      annonce_year_resolved: annonceYear || "",
      used_year_filter: usedYearFilter,
      annonce_cc_resolved: annonceCC || "",

      matched_marque: accept ? (getMarqueField(best) || get(best, "Marque") || "") : "",
      matched_modele: accept ? (getModeleField(best) || get(best, "Modèle") || "") : "",
      matched_generations: accept ? (get(best, "Spéc/Génération") || get(best, "Spec/Generation") || "") : "",
      matched_coloris: accept ? (get(best, "Coloris commercial") || "") : "",
      matched_annee_debut: accept ? (get(best, "Année début") || getYearStartField(best) || "") : "",
      matched_annee_fin: accept ? (get(best, "Année fin") || getYearEndField(best) || "") : "",
      matched_cylindree: accept ? (get(best, "Cylindrée (cc)") || "") : "",

      matched_score: accept ? Number(bestScore.toFixed(3)) : 0,
      matching_engine: accept ? "AUTO_V10_SAFE_ANTI_UPGRADE" : "NO_MATCH",
      needs_review: !accept,
      reason_no_match: accept ? "" : "below_threshold_or_no_candidate_after_gates",

      _match_debug: {
        detectedBrand: brandAnnonce || null,
        adNumbers,
        dominantGateRejectedCount,
        bestModelDominants: bestPrepared ? (bestPrepared.dominants || []) : [],
        covAlphaBest: Number(bestCov.toFixed(3)),
        jacBest: Number(bestJac.toFixed(3)),
        minCovAlpha: MIN_COV_ALPHA,
        minAccept: MIN_ACCEPT,
        ccPenaltyApplied,
        ccResolved: annonceCC || 0,
        adTokensCount: adTok.length,
      }
    }
  });
}

return results;

// ===============================
// MATCHING MODELES vs ANNONCES (v10 - aligned with your real keys)
// - Fix TITLE/PRICE/CC/DESC based on your latest scrape example
// - Matching uses a rich "titlePlus" (brand/model/version/cc/desc)
// - Output keeps "*" keys, removes "/" keys
// ===============================

const items = $input.all().map(i => i.json);

// =====================================================
// 1) CONFIG DES CLES (ANNONCE + MODELE) — UPDATED
// =====================================================
const K = {
  ANNONCE: {
    // ⚠️ Dans ton exemple, "text-headline-1-expanded" n'existe pas.
    // La meilleure "signature modèle" est dans text-body-1 (8) (version constructeur).
    TITLE: ["text-headline-1-expanded", "text-body-1 (8)", "relative"],

    URL: ["absolute href", "relative"],

    // ⚠️ Dans ton exemple: text-headline-1 = pseudo, prix = text-headline-1 (2) ou flex
    PRICE: ["text-headline-1 (2)", "flex"],

    DATE_DAY: ["text-caption"],
    DATE_TIME: ["text-caption (2)"],

    // vendeur (selon ton exemple)
    SELLER_NAME: ["text-headline-1 (3)", "text-headline-1"], // "Jeremy21"
    SELLER_LOCATION: ["text-body-1"],                        // "Vignoles"
    SELLER_SINCE: ["text-body-2 (2)"],                       // "Membre depuis ..."
    LAST_ACTIVITY: ["text-body-2", "text-body-2 (3)"],       // "Dernière activité ..."

    // photos / favoris
    PHOTO_1: ["size-full src"],
    PHOTO_2: ["size-full src (2)"],
    PHOTO_3: ["size-full src (3)"],
    FAV_COUNT: ["u-shadow-border-transition"],
    EXTRA_PHOTOS_TEXT: ["u-shadow-border-transition (2)"],

    // véhicule
    BRAND: ["text-body-1 (2)"],          // TRIUMPH
    MODEL: ["text-body-1 (3)"],          // parfois vide
    YEAR: ["text-body-1 (4)"],           // 2013
    KM: ["text-body-1 (5)"],             // 50000 km

    // ⚠️ Dans ton exemple, "1050" est en (7) (donc CC)
    CC_NUM: ["text-body-1 (7)"],

    // Version constructeur (souvent contient le vrai nom modèle)
    VERSION: ["text-body-1 (8)"],

    FIRST_REG: ["text-body-1 (9)"],

    COLOR: ["text-body-1 (11)"],
    LICENSE_TYPE: ["text-body-1 (12)"],

    // parfois vide
    CC_TXT: ["text-body-1 (13)"],

    // ⚠️ Ta description réelle est en (16), pas (14)
    DESC: ["text-body-1 (16)", "text-body-1 (14)"],

    // "href(5)" contient cc+brand en URL mais tu ne veux pas le garder en sortie ("/"),
    // on peut le lire pour aider le matching sans l'exporter.
    CC_HREF: ["text-body-1 href (5)"],
  },

  MODELE: {
    MARQUE: ["Marque", "marque", "MARQUE", "Brand", "brand"],
    MODELE: ["Modèle", "Modele", "modele", "Model", "MODELE", "Modèle "],
    YEAR_START: ["Année début", "Annee debut", "Year start", "yearStart"],
    YEAR_END: ["Année fin", "Annee fin", "Year end", "yearEnd"],
    CC: ["Cylindrée (cc)", "Cylindree (cc)", "cc", "CC"],
    GENERATION: ["Spéc/Génération", "Spec/Generation", "Génération", "Generation"],
    COLORIS: ["Coloris commercial", "Coloris", "Couleur", "Color"],
  }
};

// =====================================================
// 2) HELPERS
// =====================================================
const pick = (obj, keys) => {
  for (const k of keys) {
    if (obj && obj[k] !== undefined && obj[k] !== null && String(obj[k]).trim() !== "") return obj[k];
  }
  return "";
};

const normalize = (text) => {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .trim()
    .replace(/\s+/g, " ");

  s = s.replace(/\bevolution\b/g, "evo");
  s = s.replace(/\bmonster evolution\b/g, "monster evo");
  s = s.replace(/\bduke\s+125\b/g, "125 duke");
  s = s.replace(/\bmt\s*07\b/g, "mt07");

  return s;
};

const tokenize = (text) => normalize(text).split(" ").filter(t => t.length > 1);

const getMarqueField = (m) => pick(m, K.MODELE.MARQUE);
const getModeleField = (m) => pick(m, K.MODELE.MODELE);
const getYearStartField = (m) => pick(m, K.MODELE.YEAR_START);
const getYearEndField   = (m) => pick(m, K.MODELE.YEAR_END);

const getAnnonceTitle = (a) => pick(a, K.ANNONCE.TITLE) || "";
const getAnnonceUrl   = (a) => pick(a, K.ANNONCE.URL) || "";

const getAnnonceBrandRaw = (a) => pick(a, K.ANNONCE.BRAND) || "";
const getAnnonceModelRaw = (a) => pick(a, K.ANNONCE.MODEL) || "";
const getAnnonceYearRaw  = (a) => pick(a, K.ANNONCE.YEAR) || "";
const getAnnonceFirstRegRaw = (a) => pick(a, K.ANNONCE.FIRST_REG) || "";
const getAnnonceDescRaw  = (a) => pick(a, K.ANNONCE.DESC) || "";

const getAnnonceVersionRaw = (a) => pick(a, K.ANNONCE.VERSION) || "";
const getAnnonceCCNumRaw   = (a) => pick(a, K.ANNONCE.CC_NUM) || "";
const getAnnonceCCTxtRaw   = (a) => pick(a, K.ANNONCE.CC_TXT) || "";

// =====================================================
// 3) SIMILARITE
// =====================================================
const jaccard = (a, b) => {
  const sa = new Set(a), sb = new Set(b);
  let inter = 0;
  for (const v of sa) if (sb.has(v)) inter++;
  const union = new Set([...sa, ...sb]).size;
  return union === 0 ? 0 : inter / union;
};

const isNumberToken = (t) => /^\d+$/.test(t);
const isYearLike = (n) => n >= 1900 && n <= 2099;

const pickStructNums = (tokens) => {
  const out = [];
  for (const t of tokens) {
    if (!isNumberToken(t)) continue;
    const n = parseInt(t, 10);
    if (!n) continue;
    if (isYearLike(n)) continue;
    if (n >= 2 && n <= 15) out.push(n);
    else if (n >= 50 && n <= 2500) out.push(n);
  }
  return out;
};

// Levenshtein courte
const levToken = (a, b, maxDist = 1) => {
  a = a || ""; b = b || "";
  if (Math.abs(a.length - b.length) > maxDist) return maxDist + 1;

  const dp = Array(b.length + 1);
  for (let j = 0; j <= b.length; j++) dp[j] = j;

  for (let i = 1; i <= a.length; i++) {
    let prev = dp[0];
    dp[0] = i;
    let bestRow = dp[0];

    for (let j = 1; j <= b.length; j++) {
      const tmp = dp[j];
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      dp[j] = Math.min(dp[j] + 1, dp[j - 1] + 1, prev + cost);
      prev = tmp;
      if (dp[j] < bestRow) bestRow = dp[j];
    }
    if (bestRow > maxDist) return maxDist + 1;
  }
  return dp[b.length];
};

function computeScoreModelOnly(titleNorm, titleTokens, pm) {
  const W_JACC = 85;
  const W_SUBSTR = 25;
  const W_ALPHA_INTER = 18;
  const W_FUZZY_SHORT = 12;
  const MIN_ALPHA_MATCH = 1;

  const titleAlpha = titleTokens.filter(t => !isNumberToken(t));
  const modelAlpha = pm.modelTokens.filter(t => !isNumberToken(t));
  if (modelAlpha.length === 0) return { score: 0, jacc: 0 };

  // gate chiffres structurants
  const modelNums = pickStructNums(pm.modelTokens);
  const titleNums = pickStructNums(titleTokens);
  if (modelNums.length && titleNums.length) {
    const sA = new Set(modelNums);
    let okNum = false;
    for (const n of titleNums) if (sA.has(n)) { okNum = true; break; }
    if (!okNum) return { score: 0, jacc: 0 };
  }

  let alphaExact = 0;
  const titleAlphaSet = new Set(titleAlpha);
  for (const mt of modelAlpha) if (titleAlphaSet.has(mt)) alphaExact++;

  let alphaFuzzy = 0;
  if (alphaExact === 0) {
    for (const mt of modelAlpha) {
      if (mt.length >= 2 && mt.length <= 4) {
        for (const tt of titleAlpha) {
          if (tt.length >= 2 && tt.length <= 4 && levToken(mt, tt, 1) <= 1) {
            alphaFuzzy++;
            break;
          }
        }
      }
    }
  }

  if ((alphaExact + alphaFuzzy) < MIN_ALPHA_MATCH) return { score: 0, jacc: 0 };

  let score = 0;
  if (pm.modelName && titleNorm.includes(pm.modelName)) score += W_SUBSTR;

  const j = jaccard(titleTokens, pm.modelTokens);
  score += j * W_JACC;

  score += alphaExact * W_ALPHA_INTER;
  score += alphaFuzzy * W_FUZZY_SHORT;

  return { score, jacc: j };
}

// =====================================================
// 4) ANNEE + CC
// =====================================================
function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a) {
  const y1 = parseYearMonth(getAnnonceYearRaw(a));
  if (y1.year) return y1.year;

  const y2 = parseYearMonth(getAnnonceFirstRegRaw(a));
  if (y2.year) return y2.year;

  return 0;
}

function extractCCFromText(text) {
  const s = normalize(text);

  // "1050 cm³"
  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|cm 3)\b/);
  if (m) return parseInt(m[1], 10);

  // "1050"
  m = s.match(/\b(\d{2,4})\b/);
  if (m) {
    const n = parseInt(m[1], 10);
    if (n >= 50 && n <= 2500) return n;
  }
  return 0;
}

function getAnnonceCC(a) {
  // 1) champ numérique dédié (chez toi: text-body-1 (7))
  const ccNum = extractCCFromText(getAnnonceCCNumRaw(a));
  if (ccNum) return ccNum;

  // 2) champ "cc" texte (text-body-1 (13)) si dispo
  const ccTxt = extractCCFromText(getAnnonceCCTxtRaw(a));
  if (ccTxt) return ccTxt;

  // 3) fallback version / titre / description
  const ccVer = extractCCFromText(getAnnonceVersionRaw(a));
  if (ccVer) return ccVer;

  const ccTitle = extractCCFromText(getAnnonceTitle(a));
  if (ccTitle) return ccTitle;

  const ccDesc = extractCCFromText(getAnnonceDescRaw(a));
  if (ccDesc) return ccDesc;

  return 0;
}

// =====================================================
// 5) SEPARATION MODELES / ANNONCES
// =====================================================
const modeles = [];
const annonces = [];

for (const obj of items) {
  const isModele = getMarqueField(obj) && getModeleField(obj) && pick(obj, K.MODELE.CC) !== "";
  const isAnnonce = pick(obj, K.ANNONCE.URL) !== "" || pick(obj, K.ANNONCE.TITLE) !== "" || obj?.relative !== undefined;

  if (isModele) modeles.push(obj);
  else if (isAnnonce) annonces.push(obj);
}

// Si aucun modèle => forcément aucun match
// (Je ne throw pas pour éviter de casser le workflow)
if (!modeles.length) {
  return annonces.map(a => ({ json: { ...a, matched_score: 0, matched_quality: "no_match", reason_no_match: "no_model_items_detected" } }));
}

// =====================================================
// 6) INDEX PAR MARQUE
// =====================================================
const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const brand = normalize(brandRaw);
  const modelName = normalize(modelRaw);
  const modelTokens = tokenize(modelName);

  if (!brand || !modelName || modelTokens.length === 0) continue;

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;

  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const ccModel = Math.round(Number(pick(m, K.MODELE.CC) || 0)) || 0;

  const prepared = {
    raw: m,
    brand,
    modelName,
    modelTokens,
    yearStart: ys,
    yearEnd: ye,
    cc: ccModel,
  };

  if (!brandIndex.has(brand)) brandIndex.set(brand, []);
  brandIndex.get(brand).push(prepared);
}

const knownBrands = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// =====================================================
// 7) MATCHING
// =====================================================
const SCORE_THRESHOLD = 40;
const results = [];

for (const a of annonces) {
  const url = getAnnonceUrl(a);

  // ⚠️ On score sur un texte enrichi: version + marque + modèle + cc + description
  const brandField = getAnnonceBrandRaw(a);
  const modelField = getAnnonceModelRaw(a);
  const versionField = getAnnonceVersionRaw(a);
  const ccNumField = getAnnonceCCNumRaw(a);
  const ccTxtField = getAnnonceCCTxtRaw(a);
  const desc = getAnnonceDescRaw(a);
  const yearField = pick(a, K.ANNONCE.YEAR) || "";

  const titlePlus = `${versionField} ${brandField} ${modelField} ${ccNumField} ${ccTxtField} ${yearField} ${desc}`.trim();
  const titleNorm = normalize(titlePlus);
  const titleTokens = tokenize(titlePlus);

  // marque: champ marque, sinon fallback scan knownBrands
  let brandAnnonce = normalize(brandField);
  if (!brandAnnonce) {
    for (const b of knownBrands) {
      if (titleNorm.includes(b)) { brandAnnonce = b; break; }
    }
  }

  const annonceYear = pickAnnonceYear(a);
  const annonceCC = getAnnonceCC(a);

  // anti générique (mais on accepte si on a version/model/cc)
  const hasDiscriminant = !!normalize(versionField) || !!normalize(modelField) || !!annonceCC;
  const titleIsTooGeneric = titleTokens.length <= 3 && !hasDiscriminant;

  if (titleIsTooGeneric) {
    results.push({ json: buildOut(a, { url, annonceYear, annonceCC, match: null, score: 0, jacc: 0, usedYearFilter: false, reason: "too_generic_no_discriminant" }) });
    continue;
  }

  if (!brandAnnonce || !brandIndex.has(brandAnnonce)) {
    results.push({ json: buildOut(a, { url, annonceYear, annonceCC, match: null, score: 0, jacc: 0, usedYearFilter: false, reason: "brand_not_found" }) });
    continue;
  }

  const baseCandidates = brandIndex.get(brandAnnonce);
  const passes = [{ useYear: true }, { useYear: false }];

  let bestPrepared = null;
  let bestScore = 0;
  let bestJ = 0;
  let usedYearFilter = false;

  for (const pass of passes) {
    let foundInPass = false;

    for (const pm of baseCandidates) {
      if (pass.useYear && annonceYear) {
        if (annonceYear < pm.yearStart || annonceYear > pm.yearEnd) continue;
      }

      // gate CC dur
      if (annonceCC && pm.cc) {
        const diffHard = Math.abs(pm.cc - annonceCC);
        if (diffHard >= 80) continue;
      }

      let ccPenalty = 0;
      if (annonceCC && pm.cc) {
        const diff = Math.abs(pm.cc - annonceCC);
        if (diff > 2 && diff <= 30) ccPenalty = 10;
        else if (diff > 30) ccPenalty = 20;
      }

      let { score, jacc } = computeScoreModelOnly(titleNorm, titleTokens, pm);
      score = Math.max(0, score - ccPenalty);

      if (score > bestScore) {
        bestScore = score;
        bestPrepared = pm;
        bestJ = jacc;
        usedYearFilter = pass.useYear && !!annonceYear;
        foundInPass = true;
        if (bestScore >= 95) break;
      }
    }

    if (pass.useYear && foundInPass) break;
  }

  const ok = bestScore >= SCORE_THRESHOLD;
  const best = ok ? bestPrepared?.raw : null;

  results.push({
    json: buildOut(a, {
      url,
      annonceYear,
      annonceCC,
      match: best,
      score: Math.round(bestScore),
      jacc: Number(bestJ || 0).toFixed(2),
      usedYearFilter,
      reason: ok ? "" : "below_threshold"
    })
  });
}

// =====================================================
// 8) OUTPUT: keep "*" keys, remove "/" keys
// =====================================================
// D'après ton exemple: les clés marquées "/" qu'on ne garde plus
function stripUnwanted(obj) {
  const UNWANTED_KEYS = new Set([
    "text-headline-1 href",
    "text-body-1 href",
    "text-body-1 (15)",
    "text-body-1 href (5)",
    "text-headline-1 href (2)"
  ]);

  const out = {};
  for (const k in (obj || {})) {
    if (!UNWANTED_KEYS.has(k)) out[k] = obj[k];
  }
  return out;
}

function buildOut(a, ctx) {
  const score = Number(ctx.score || 0);

  let matchQuality = "no_match";
  if (score >= 75) matchQuality = "excellent";
  else if (score >= 55) matchQuality = "good";
  else if (score >= SCORE_THRESHOLD) matchQuality = "fair";

  const best = ctx.match;
  const base = stripUnwanted(a);

  return {
    ...base,

    // champs lisibles
    annonce_url: ctx.url || "",
    annonce_prix: pick(a, K.ANNONCE.PRICE) || "",
    annonce_date_jour: pick(a, K.ANNONCE.DATE_DAY) || "",
    annonce_date_heure: pick(a, K.ANNONCE.DATE_TIME) || "",

    vendeur_nom: pick(a, K.ANNONCE.SELLER_NAME) || "",
    vendeur_ville: pick(a, K.ANNONCE.SELLER_LOCATION) || "",
    vendeur_membre_depuis: pick(a, K.ANNONCE.SELLER_SINCE) || "",
    vendeur_derniere_activite: pick(a, K.ANNONCE.LAST_ACTIVITY) || "",

    photo_1: pick(a, K.ANNONCE.PHOTO_1) || "",
    photo_2: pick(a, K.ANNONCE.PHOTO_2) || "",
    photo_3: pick(a, K.ANNONCE.PHOTO_3) || "",
    nb_favoris: pick(a, K.ANNONCE.FAV_COUNT) || "",

    vehicule_marque: pick(a, K.ANNONCE.BRAND) || "",
    vehicule_modele: pick(a, K.ANNONCE.MODEL) || "",
    vehicule_version: pick(a, K.ANNONCE.VERSION) || "",
    vehicule_annee: pick(a, K.ANNONCE.YEAR) || "",
    vehicule_km: pick(a, K.ANNONCE.KM) || "",
    vehicule_cc: pick(a, K.ANNONCE.CC_NUM) || pick(a, K.ANNONCE.CC_TXT) || "",
    annonce_description: pick(a, K.ANNONCE.DESC) || "",

    annonce_year_resolved: ctx.annonceYear || "",
    annonce_cc_resolved: ctx.annonceCC || "",
    used_year_filter: !!ctx.usedYearFilter,

    matched_marque: best ? (getMarqueField(best) || "") : "",
    matched_modele: best ? (getModeleField(best) || "") : "",
    matched_generations: best ? (pick(best, K.MODELE.GENERATION) || "") : "",
    matched_coloris: best ? (pick(best, K.MODELE.COLORIS) || "") : "",
    matched_annee_debut: best ? (pick(best, K.MODELE.YEAR_START) || "") : "",
    matched_annee_fin: best ? (pick(best, K.MODELE.YEAR_END) || "") : "",

    matched_score: score,
    matched_quality: matchQuality,
    matched_jaccard: String(ctx.jacc || "0.00"),
    needs_review: !(score >= SCORE_THRESHOLD),
    reason_no_match: ctx.reason || "",
  };
}

return results;

// =====================================================
// MATCHING v9.3.2 (BRAND KEY FIX) — LBC 2026 KEYS (u_moto_model + cubic_capacity)
// Fix principal:
// - Canonicalise la marque via brandKey() => "CF MOTO" == "CFMOTO"
// - cleanModelFromHref2 retire la marque même si espaces/variantes
// - Toujours return [{json:{...}}] (n8n OK)
// ✅ MAJ KEYS 2026 (selon ton rename columns 1):
// - Title: text-body-1 (8) (priorité) puis text-headline-1-expanded puis Nom_annonce/relative
// - Desc: annonce_description (priorité) puis text-body-1 (16) puis text-body-1 (14) puis Description_complete
// - Brand: text-body-1 (2) (priorité) puis Marque_scrap/annonce_brand_input
// - Year: text-body-1 (4) puis text-body-1 (9) puis Annee_du_modele
// - KM: text-body-1 (5) puis "Kilomètrage" / kilometrage
// - CC: href cubic_capacity via text-body-1 href (5) (priorité) puis champ texte cc: text-body-1 (7)
// - href marque: text-body-1 href (2)
// - href modèle: text-body-1 href (3)
// =====================================================

const allItems = $input.all().map(i => i.json);

// -------------------------
// GET / PICK
// -------------------------
const get = (obj, ...keys) => {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
};

const pick = (obj, keys) => {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
};

// -------------------------
// Champs annonces (✅ NEW KEYS 2026 + compat)
// -------------------------
const getAnnonceTitle = (a) =>
  get(a,
    "text-body-1 (8)",           // ✅ prioritaire (souvent = "BMW R1200GS ...")
    "text-headline-1-expanded",
    "text-headline-1",
    "Nom_annonce",
    "annonce_title",
    "relative"
  );

const getAnnonceDesc = (a) =>
  get(a,
    "annonce_description",       // ✅ ton champ propre (fix “1 seule desc”)
    "text-body-1 (16)",          // ✅ nouvelle position description (si dispo)
    "text-body-1 (14)",          // fallback ancien
    "Description_complete",
    "description",
    "annonce_desc"
  );

const getAnnonceUrl = (a) =>
  get(a,
    "Url_Https",
    "absolute href",
    "annonce_url",
    "relative"
  );

// ✅ Brand: maintenant text-body-1 (2)
const getAnnonceBrand = (a) =>
  get(a,
    "text-body-1 (2)",
    "Marque_scrap",
    "annonce_brand_input"
  );

// année brute: (4) puis (9)
const getAnnonceYearRaw1 = (a) => get(a, "text-body-1 (4)", "Annee_du_modele", "annonce_year_input_1");
const getAnnonceYearRaw2 = (a) => get(a, "text-body-1 (9)", "Mise_en_circulation", "annonce_year_input_2");

// ✅ CC via filtre LBC (le + fiable) : href(5)
const getAnnonceCCHref = (a) => get(a, "text-body-1 href (5)");

// ✅ modèle via href(3)
const getAnnonceModelHref = (a) => get(a, "text-body-1 href (3)");

// ✅ href marque LBC: href(2)
const getAnnonceBrandHref = (a) => get(a, "text-body-1 href (2)", "text-body-1 href");

// km / seller / payment
const getAnnonceKmField  = (a) => get(a, "text-body-1 (5)", "Kilomètrage", "kilometrage", "Nombre_de_kilometres");
const getAnnonceSeller   = (a) => get(a, "text-headline-1", "text-headline-1 (3)", "Nom_vendeur", "nom du vendeur pro", "seller_name", "Vendeur");
const getAnnoncePayment  = (a) => get(a, "Paiement_ou_SIREN");

// -------------------------
// Champs modèles (référentiel)
// -------------------------
const getModeleField = (m) => pick(m, ["Modèle","Modele","modele","Model","MODELE","Modèle "]) || "";
const getMarqueField = (m) => pick(m, ["Marque","marque","MARQUE","Brand","brand"]) || "";
const getYearStartField = (m) => pick(m, ["Année début","Annee debut","Année début ","Year start","yearStart"]) || "";
const getYearEndField   = (m) => pick(m, ["Année fin","Annee fin","Année fin ","Year end","yearEnd"]) || "";

// -------------------------
// Normalisation / Tokenize
// -------------------------
const STOP = new Set([
  "moto","motos","scooter","roadster","trail","enduro","cross",
  "vend","vente","vends","urgent","etat","tres","super","parfait","excellent",
  "paiement","securise","option","full","abs","a2","ct","ok",
  "km","kms","kilometrage","kilometres","boite","vitesse","manuelle","automatique",
  "prix","euro","eur","garantie","factures","entretien","revision","controle"
]);

function normalize(text) {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  s = s.replace(/_/g, " ");
  s = s.replace(/[/|]/g, " ");
  s = s.replace(/[^a-z0-9]+/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  s = s.replace(/\b(mt)\s*0?(\d{2})\b/g, "$1$2");
  s = s.replace(/\b(fz)\s*(\d)\b/g, "$1$2");
  s = s.replace(/\b(gs)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(dl)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(v\s*strom)\b/g, "vstrom");
  s = s.replace(/\b(v[-\s]?strom)\b/g, "vstrom");
  s = s.replace(/\b(dr)\s*z\b/g, "drz");

  return s;
}

// ✅ clé marque canonique : supprime espaces (CF MOTO == CFMOTO)
function brandKey(brand) {
  return normalize(brand).replace(/\s+/g, "");
}

function splitAlphaNum(tok) {
  const parts = String(tok).match(/[a-z]+|\d+/g);
  return parts && parts.length > 1 ? parts : [];
}

function tokenizeAny(text) {
  const n = normalize(text);
  if (!n) return [];
  const raw = n.split(" ").filter(Boolean);
  const out = [];

  for (const t0 of raw) {
    out.push(t0);
    const parts = splitAlphaNum(t0);
    if (parts.length) out.push(...parts);
  }

  return out.filter(t => {
    if (!t) return false;
    if (STOP.has(t)) return false;
    if (/^\d+$/.test(t)) return true;
    return t.length >= 2;
  });
}

// ✅ modèle : garde token original + sous-parties (ex: "r1m" => r1m + r + 1 + m)
function tokenizeModel(text) {
  const n = normalize(text);
  if (!n) return [];
  const raw = n.split(" ").filter(Boolean);
  const out = [];

  for (const t0 of raw) {
    out.push(t0); // keep original
    const parts = splitAlphaNum(t0);
    if (parts.length) out.push(...parts);
  }

  return out.filter(t => {
    if (!t) return false;
    if (STOP.has(t)) return false;
    if (/^\d+$/.test(t)) return true;
    return t.length >= 2;
  });
}

const tokensAlphaOnly = (tokens) => tokens.filter(t => /[a-z]/.test(t) && t.length >= 2);

// -------------------------
// Parsing année
// -------------------------
function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a, adText) {
  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const m = String(adText || "").match(/\b(19|20)\d{2}\b/);
  if (m) return parseInt(m[0], 10);

  return 0;
}

// -------------------------
// CC (✅ NEW KEYS 2026)
// -------------------------
function ccFromHref(href) {
  const s = String(href || "");
  const m = s.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|cm 3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  // NEW: si on a juste "1050" (sans "cc"), on ne guess PAS ici
  return 0;
}

function extractNumbers(text) {
  const raw = String(text || "")
    .replace(/\b(\d{1,6})\s*km\b/gi, " ")
    .replace(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/g, " ");
  const s = normalize(raw);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
}

function inferCCFromNumbers(adText, annonceYear) {
  const nums = extractNumbers(adText);
  const candidates = nums.filter(n => n >= 80 && n <= 2500 && (!annonceYear || n !== annonceYear));
  if (!candidates.length) return 0;
  return Math.max(...candidates);
}

function getAnnonceCC(a, adText, annonceYear) {
  // 1) href cubic_capacity (priorité)
  const ccH = ccFromHref(getAnnonceCCHref(a));
  if (ccH) return ccH;

  // 2) champ texte CC dédié (✅ text-body-1 (7) = "1050")
  const ccTxt = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc");
  if (ccTxt) {
    // si purement numérique, on accepte direct (ex: "1050")
    const n = String(ccTxt).replace(/[^\d]/g, "");
    if (n && n.length >= 2 && n.length <= 4) return parseInt(n, 10);

    const ccField = extractCCFromText(ccTxt);
    if (ccField) return ccField;
  }

  // 3) texte global
  const ccT = extractCCFromText(adText);
  if (ccT) return ccT;

  // 4) dernier recours
  const ccN = inferCCFromNumbers(adText, annonceYear || 0);
  if (ccN) return ccN;

  return 0;
}

// -------------------------
// u_moto_brand / u_moto_model depuis href
// -------------------------
function decodePlus(s) { return String(s || "").replace(/\+/g, " "); }

function extractBrandFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_brand:([^+&]+)/i);
  if (!m) return "";
  try { return decodeURIComponent(decodePlus(m[1])); }
  catch (e) { return decodePlus(m[1]); }
}

function extractModelFromHref2(href2) {
  const h = String(href2 || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try { return decodeURIComponent(decodePlus(m[1])); }
  catch (e) { return decodePlus(m[1]); }
}

function prettyBrand(raw) {
  const s = String(raw || "").trim();
  if (!s) return "";
  if (s === s.toUpperCase()) return s;
  return s
    .toLowerCase()
    .split(/\s+/)
    .map(w => w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ");
}

function resolveBrandForOutput(a, hrefBrand) {
  const rawHref = extractBrandFromHref(hrefBrand);
  const rawField = getAnnonceBrand(a);
  return prettyBrand(rawHref || rawField);
}

function cleanModelFromHref2(modelStr, brandRawOrNorm) {
  if (!modelStr) return "";
  const original = String(modelStr).replace(/_/g, " ").trim();
  const n = normalize(original);

  if (n === "autre" || n.endsWith(" autre") || n.includes(" autre ")) return "";

  if (brandRawOrNorm) {
    const bk = brandKey(brandRawOrNorm);
    const origTokens = original.split(/\s+/);

    for (let take = Math.min(4, origTokens.length); take >= 1; take--) {
      const head = origTokens.slice(0, take).join(" ");
      if (brandKey(head) === bk) {
        return origTokens.slice(take).join(" ").trim();
      }
    }
  }

  return original;
}

function isHref2Autre(href2) {
  const raw = extractModelFromHref2(href2);
  const n = normalize(raw);
  return !raw || n === "autre" || n.endsWith(" autre") || n.includes(" autre ");
}

function extractModelHintFromTitle(title, brandRawOrNorm) {
  const t = String(title || "").trim();
  if (!t) return "";

  let s = t;

  // retire marque si au début
  if (brandRawOrNorm) {
    const bk = brandKey(brandRawOrNorm);
    const toks = s.split(/\s+/);
    for (let take = Math.min(4, toks.length); take >= 1; take--) {
      const head = toks.slice(0, take).join(" ");
      if (brandKey(head) === bk) {
        s = toks.slice(take).join(" ").trim();
        break;
      }
    }
  }

  s = s.replace(/\b(neuf|neuve|garantie|disponible|stock|espace|motos|moto|ans|km)\b/gi, " ");

  const toksAll = tokenizeModel(s);

  // ✅ retirer la marque partout (pas seulement en tête)
  let toks = toksAll;
  if (brandRawOrNorm) {
    const bk = brandKey(brandRawOrNorm);
    toks = toksAll.filter(tk => brandKey(tk) !== bk);
  }

  const keep = [];
  for (const t0 of toks) {
    if (/^(19|20)\d{2}$/.test(t0)) continue;
    keep.push(t0);
    if (keep.length >= 4) break;
  }
  return keep.length ? keep.join(" ") : "";
}

// -------------------------
// Similarités
// -------------------------
function jaccard(aTokens, bTokens) {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}

function coverageSet(adSet, modelTokens) {
  if (!modelTokens.length) return 0;
  let hit = 0;
  for (const t of modelTokens) if (adSet.has(t)) hit++;
  return hit / modelTokens.length;
}

function getModelDominantTokens(modelRaw) {
  const n = normalize(modelRaw);
  const nums = n.match(/\b\d{3,4}\b/g) || [];
  if (nums.length) return nums.map(Number);
  const toks = tokenizeAny(modelRaw);
  return toks.filter(t => /\d/.test(t) || t.length >= 4);
}

function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => p.trim()).filter(Boolean);
  return Array.from(new Set(parts.map(p => normalize(p)).filter(Boolean)));
}

// -------------------------
// Seller flags
// -------------------------
function parseKmFromField(s) {
  const str = String(s || "");
  const m = str.replace(/\u202f/g, " ").replace(/\s/g, "").match(/(\d{1,6})km/i);
  return m ? parseInt(m[1], 10) : 0;
}

function detectSellerFlags(a, adText) {
  const sellerName = String(getAnnonceSeller(a) || "").trim();
  const payment = String(getAnnoncePayment(a) || "").trim();
  const km = parseKmFromField(getAnnonceKmField(a));
  const blob = `${sellerName} ${payment} ${adText}`;

  const proSignals = /\b(siret|siren|tva|rcs|immatricul|professionnel|vendeur\s*pro|concession\b|concessionnaire|garage|showroom|reprise|financement|leasing|cr[eé]dit)\b/i;
  const proFalseContext = /\b(entretenu(e)?|revision|r[eé]vis[eé])\s+(chez|en)\s+(le|la)\s+(concessionnaire|garage)\b/i;
  const companySignals = /\b(sarl|sas|eurl|auto-entrepreneur|entreprise|moto(s)?\s*occ|occasion(s)?|motors|autos?)\b/i;

  let isPro = false;
  if (sellerName) isPro = companySignals.test(sellerName) || /\b(siret|siren)\b/i.test(blob);
  if (!isPro && proSignals.test(blob) && !proFalseContext.test(blob)) isPro = true;

  const newTrue = /\b(0\s*km|0\s*kms|jamais\s+immatricul[eé]e?|moto\s+neuve|vehicule\s+neuf|neuf\s+jamais\s+roul[eé])\b/i;
  const newFalseParts = /\b(batterie|pneu(x)?|plaquette(s)?|kit\s*chaine|chaine|disque(s)?|huile|vidange|filtre)\s+neuf(s|ve|ves)?\b/i;

  let isNew = newTrue.test(adText);
  if (!isNew && /\b(neuf|neuve)\b/i.test(adText) && !newFalseParts.test(adText)) isNew = false;

  return { sellerName, km, isPro, isNew };
}

// -------------------------
// Out of scope (ne SKIP pas si modelHint valide)
// -------------------------
function isNonMotoListing(a, adTextUsed, modelHintClean) {
  const typeField = normalize(get(a, "text-body-1 (10)", "Type_vehicule", "type", "vehicle_type"));

  if (modelHintClean && String(modelHintClean).trim() !== "") return { skip: false, reason: "" };

  if (typeField && typeField !== "moto") return { skip: true, reason: `type_not_moto:${typeField}` };

  const title = normalize(getAnnonceTitle(a));
  const desc  = normalize(getAnnonceDesc(a));
  const blob  = `${title} ${desc} ${normalize(adTextUsed)}`;

  const reNonMoto = /\b(trottinette|edpm|nami|dualtron|kaabo|weped|speedway|monoroue|gyropode|hoverboard)\b/i;
  const reParts   = /\b(piece|pieces|accessoire|accessoires|casque|gants|blouson|bottes|pneu|pneus|jante|echappement|ligne|silencieux)\b/i;

  if (reNonMoto.test(blob)) return { skip: true, reason: "non_moto_vehicle" };
  if (reParts.test(blob))   return { skip: true, reason: "parts_or_accessories" };

  return { skip: false, reason: "" };
}

// -------------------------
// Split modèles / annonces
// -------------------------
const modeles = [];
const annonces = [];

for (const item of allItems) {
  const isModele = !!getMarqueField(item) && !!getModeleField(item) &&
    (get(item, "Cylindrée (cc)", "Type (M/S/E)", "Type(M/S/E)", "Type (M\\/S\\/E)") !== "");

  const isAnnonce = get(item, "text-body-1 (8)", "text-headline-1-expanded", "relative", "Url_Https", "absolute href", "annonce_url") !== "";

  if (isModele) modeles.push(item);
  else if (isAnnonce) annonces.push(item);
}

if (!modeles.length) {
  return annonces.map(a => ({ json: { ...a, matching_engine: "NO_MODELS_INPUT", matched_score: 0, needs_review: true } }));
}

// -------------------------
// Index marques (sur brandKey)
// -------------------------
const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const bKey = brandKey(brandRaw);
  if (!bKey) continue;

  const variants = modelVariants(modelRaw);
  if (!variants.length) continue;

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;
  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const cc = Math.round(Number(get(m, "Cylindrée (cc)") || 0)) || 0;

  // ✅ IMPORTANT: tokenizeModel + tokensAlphaOnly (>=2 lettres)
  const variantAlphaTokens = variants
    .map(v => tokensAlphaOnly(tokenizeModel(v)))
    .filter(t => t.length);

  if (!variantAlphaTokens.length) continue;

  const doms = getModelDominantTokens(modelRaw);
  const modelNoSpace = normalize(modelRaw).replace(/\s+/g, "");

  const prepared = {
    raw: m,
    brandRaw,
    bKey,
    ys,
    ye,
    cc,
    variants,
    variantAlphaTokens,
    combinedTok: tokenizeAny(`${brandRaw} ${modelRaw}`),
    dominants: doms,
    modelNoSpace
  };

  if (!brandIndex.has(bKey)) brandIndex.set(bKey, []);
  brandIndex.get(bKey).push(prepared);
}

const knownBrandKeys = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// -------------------------
// Seuils (-10%) + CC hard gate
// -------------------------
const MIN_COV_ALPHA = 0.54;
const MIN_ACCEPT    = 0.648;
const CC_BLOCK_DIFF = 315;
const CC_PENALTY    = 0.072;

const CC_HARD_GATE  = 75; // ✅ demandé

function computeScore(adTok, adSet, p) {
  let bestCov = 0;
  for (const vat of p.variantAlphaTokens) {
    const cov = coverageSet(adSet, vat);
    if (cov > bestCov) bestCov = cov;
  }
  const jac = jaccard(adTok, p.combinedTok);
  const score = (0.88 * bestCov) + (0.12 * jac);
  return { score, bestCov, jac };
}

// ✅ rescue quand le modelHint contient clairement le modèle
function hintRescue(modelHint, p) {
  if (!modelHint) return false;
  const hNorm = normalize(modelHint);
  if (!hNorm) return false;

  const hNoSpace = hNorm.replace(/\s+/g, "");
  const mNoSpace = (p.modelNoSpace || "").replace(/\s+/g, "");

  if (mNoSpace && hNoSpace.includes(mNoSpace)) return true;

  if (p.variants && p.variants.length) {
    for (const v of p.variants) {
      const vNorm = normalize(v);
      if (vNorm && hNorm.includes(vNorm)) return true;
    }
  }

  const hTok = new Set(tokensAlphaOnly(tokenizeAny(modelHint)));
  if (p.variantAlphaTokens && p.variantAlphaTokens.length) {
    for (const vat of p.variantAlphaTokens) {
      let hit = 0;
      for (const t of vat) if (hTok.has(t)) hit++;
      if (hit >= 1) return true;
    }
  }

  return false;
}

// -------------------------
// MATCHING
// -------------------------
const results = [];

for (const a of annonces) {
  const title = getAnnonceTitle(a);
  const desc  = getAnnonceDesc(a);
  const url   = getAnnonceUrl(a);

  // ✅ NEW hrefs
  const href2 = getAnnonceModelHref(a) || ""; // text-body-1 href (3)
  const href4 = getAnnonceCCHref(a) || "";    // text-body-1 href (5)

  const hrefBrand = getAnnonceBrandHref(a) || "";
  const brandOut  = resolveBrandForOutput(a, hrefBrand);

  const brandFromHrefRaw = extractBrandFromHref(hrefBrand);
  const brandFromHrefKey = brandKey(brandFromHrefRaw);

  const brandFromFieldRaw = getAnnonceBrand(a);
  const brandFromFieldKey = brandKey(brandFromFieldRaw);

  const ccTxtField = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc");

  const adTextBase = `${title} ${desc} ${ccTxtField} ${href4}`.trim();
  const adNormBase = normalize(adTextBase);

  let brandAnnonceKey = brandFromHrefKey || brandFromFieldKey;

  if (!brandAnnonceKey) {
    const blobKey = brandKey(adNormBase);
    for (const bk of knownBrandKeys) {
      if (blobKey.includes(bk)) { brandAnnonceKey = bk; break; }
    }
  }

  const rawModelFromHref2 = extractModelFromHref2(href2);

  let modelHint = cleanModelFromHref2(
    rawModelFromHref2,
    brandFromHrefRaw || brandFromFieldRaw
  );

  const titleHint = extractModelHintFromTitle(
    title,
    brandFromHrefRaw || brandFromFieldRaw
  );

  const hintHasDigits = (s) => /\b\d{2,4}\b/.test(normalize(s));
  const hintTokenCount = (s) => tokenizeModel(s).length;

  const modelHintGeneric =
    !modelHint ||
    (!hintHasDigits(modelHint) && hintTokenCount(modelHint) <= 1);

  if (modelHintGeneric && titleHint) {
    const titleBetter = hintHasDigits(titleHint) || hintTokenCount(titleHint) >= 2;
    if (titleBetter) modelHint = titleHint;
  }

  if (!modelHint && isHref2Autre(href2)) {
    modelHint = titleHint;
  }

  const matchedModeleFallback = modelHint ? String(modelHint).trim() : "";
  const adTextUsed = modelHint ? `${adTextBase} ${modelHint}`.trim() : adTextBase;

  const annonceYear = pickAnnonceYear(a, adTextUsed);
  const annonceCC   = getAnnonceCC(a, adTextUsed, annonceYear);
  const sellerFlags = detectSellerFlags(a, adTextUsed);

  const nonMoto = isNonMotoListing(a, adTextUsed, modelHint);
  if (nonMoto.skip) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",
        cc_source_href: ccFromHref(href4) || "",
        seller_is_pro: sellerFlags.isPro,
        seller_is_new: sellerFlags.isNew,

        matched_ok: false,
        matched_quality: "no_match",
        matched_marque: brandOut || "",
        matched_modele: matchedModeleFallback,
        matched_generations: "",
        matched_coloris: "",
        matched_annee_debut: "",
        matched_annee_fin: "",
        matched_cylindree: "",
        matched_score: 0,

        matching_engine: "SKIP_OUT_OF_SCOPE",
        needs_review: false,
        reason_no_match: nonMoto.reason,
        _match_debug: {
          detectedBrand: normalize(brandFromHrefRaw || brandFromFieldRaw) || null,
          brandFromHref: normalize(brandFromHrefRaw) || null,
          hrefBrand: hrefBrand || null,
          href2,
          modelHint
        }
      }
    });
    continue;
  }

  if (!brandAnnonceKey || !brandIndex.has(brandAnnonceKey)) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",
        cc_source_href: ccFromHref(href4) || "",
        seller_is_pro: sellerFlags.isPro,
        seller_is_new: sellerFlags.isNew,

        matched_ok: false,
        matched_quality: "no_match",
        matched_marque: "",
        matched_modele: matchedModeleFallback,
        matched_generations: "",
        matched_coloris: "",
        matched_annee_debut: "",
        matched_annee_fin: "",
        matched_cylindree: "",
        matched_score: 0,

        matching_engine: "NO_MATCH",
        needs_review: true,
        reason_no_match: "brand_not_in_ref",
        _match_debug: {
          detectedBrand: normalize(brandFromHrefRaw || brandFromFieldRaw) || null,
          brandFromHref: normalize(brandFromHrefRaw) || null,
          hrefBrand: hrefBrand || null,
          brandAnnonceKey,
          href2,
          modelHint,
          adTextPreview: adTextUsed.slice(0, 250),
        }
      }
    });
    continue;
  }

  const adTok = tokenizeAny(adTextUsed);
  const adSet = new Set(adTok);
  const adNumbers = extractNumbers(adTextUsed);

  let baseCandidates = brandIndex.get(brandAnnonceKey) || [];

  if (annonceCC) {
    const filtered = baseCandidates.filter(p => !p.cc || Math.abs(p.cc - annonceCC) <= CC_BLOCK_DIFF);
    if (filtered.length >= 3) baseCandidates = filtered;
  }

  const passes = [{ useYear: true }, { useYear: false }];

  let bestPrepared = null;
  let bestScore = 0;
  let bestCov = 0;
  let bestJac = 0;
  let usedYearFilter = false;
  let ccPenaltyApplied = false;
  let dominantGateRejectedCount = 0;

  let ccHardGateRejectedCount = 0;

  for (const pass of passes) {
    let foundInPass = false;

    for (const p of baseCandidates) {
      if (pass.useYear && annonceYear) {
        if (annonceYear < p.ys || annonceYear > p.ye) continue;
      }

      const hasHint = !!(modelHint && String(modelHint).trim());
      const hasHref2Model = !!(rawModelFromHref2 && String(rawModelFromHref2).trim());
      const relaxDominantGate = hasHint || hasHref2Model;

      let hintBypass = false;

      if (hasHint) {
        const modelNoSpace = p.modelNoSpace || "";
        const hintNoSpace = normalize(modelHint).replace(/\s+/g, "");
        if (modelNoSpace && hintNoSpace.includes(modelNoSpace)) hintBypass = true;

        if (!hintBypass && p.dominants && p.dominants.length) {
          const hintTok = new Set(tokenizeAny(modelHint));
          for (const d of p.dominants) {
            if (typeof d === "number") {
              if (adNumbers.includes(d)) { hintBypass = true; break; }
            } else {
              if (hintTok.has(String(d))) { hintBypass = true; break; }
            }
          }
        }
      }

      if (!relaxDominantGate && !hintBypass && p.dominants && p.dominants.length) {
        let dominantHit = false;
        for (const d of p.dominants) {
          if (typeof d === "number") {
            if (adNumbers.includes(d)) { dominantHit = true; break; }
          } else {
            if (adSet.has(String(d))) { dominantHit = true; break; }
          }
        }
        if (!dominantHit) { dominantGateRejectedCount++; continue; }
      }

      let { score, bestCov: covA, jac } = computeScore(adTok, adSet, p);

      const canRescue = hintRescue(modelHint, p);
      if (covA < MIN_COV_ALPHA) {
        if (!canRescue) continue;
        covA = MIN_COV_ALPHA;
        score = Math.max(score, MIN_ACCEPT - 0.01);
      }

      let finalScore = score;

      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);

        // ✅ CC hard gate
        if (diff >= CC_HARD_GATE) { ccHardGateRejectedCount++; continue; }

        if (diff >= CC_BLOCK_DIFF) continue;
        if (diff > 50) { finalScore = Math.max(0, finalScore - CC_PENALTY); ccPenaltyApplied = true; }
      }

      if (finalScore > bestScore) {
        bestScore = finalScore;
        bestPrepared = p;
        bestCov = covA;
        bestJac = jac;
        usedYearFilter = pass.useYear && !!annonceYear;
        foundInPass = true;
      }
    }

    if (pass.useYear && foundInPass) break;
  }

  const accept = !!bestPrepared && bestScore >= MIN_ACCEPT;
  const best = accept ? bestPrepared.raw : null;

  results.push({
    json: {
      ...a,
      annonce_title: title,
      annonce_url: url,
      annonce_year_resolved: annonceYear || "",
      used_year_filter: usedYearFilter,
      annonce_cc_resolved: annonceCC || "",
      cc_source_href: ccFromHref(href4) || "",
      seller_is_pro: sellerFlags.isPro,
      seller_is_new: sellerFlags.isNew,

      matched_ok: accept,
      matched_quality: accept ? "auto_match" : "no_match",

      matched_marque: accept ? (getMarqueField(best) || "") : (brandOut || ""),
      matched_modele: accept ? (getModeleField(best) || "") : matchedModeleFallback,
      matched_generations: accept ? (get(best, "Spéc/Génération", "Spec/Generation") || "") : "",
      matched_coloris: accept ? (get(best, "Coloris commercial") || "") : "",
      matched_annee_debut: accept ? (get(best, "Année début") || getYearStartField(best) || "") : "",
      matched_annee_fin: accept ? (get(best, "Année fin") || getYearEndField(best) || "") : "",
      matched_cylindree: accept ? (get(best, "Cylindrée (cc)") || "") : "",

      matched_score: accept ? Number(bestScore.toFixed(3)) : 0,
      matched_jaccard: Number(bestJac.toFixed(3)),
      matching_engine: accept ? "AUTO_V9_3_2_BRANDKEY_LBC2026" : "NO_MATCH",
      needs_review: !accept,
      reason_no_match: accept ? "" : "below_threshold_or_no_candidate_after_gates",

      _match_debug: {
        detectedBrand: normalize(brandFromHrefRaw || brandFromFieldRaw) || null,
        brandFromHref: normalize(brandFromHrefRaw) || null,
        hrefBrand: hrefBrand || null,
        brandAnnonceKey,
        adTextPreview: adTextUsed.slice(0, 250),
        href2,
        modelHint,
        adNumbers,
        dominantGateRejectedCount,

        ccHardGate: CC_HARD_GATE,
        ccHardGateRejectedCount,

        covAlphaBest: Number(bestCov.toFixed(3)),
        jacBest: Number(bestJac.toFixed(3)),
        minCovAlpha: MIN_COV_ALPHA,
        minAccept: MIN_ACCEPT,
        ccPenaltyApplied,
        ccResolved: annonceCC || 0,
        adTokensCount: adTok.length,
      }
    }
  });
}

return results;

// ===============================
// HELPERS
// ===============================
const CURRENT_YEAR = 2026;

function extractFavoris(value) {
  if (!value) return 0;
  const m = String(value).match(/(\d+)\s*$/); // prend le dernier nombre
  return m ? parseInt(m[1], 10) : 0;
}
function extractCC(value) {
  if (!value) return "";

  const m = String(value).match(/(\d{2,4}(\.\d+)?)/);
  if (!m) return "";

  const cc = parseFloat(m[1]);

  // ❌ si inférieur à 49.8 → ne rien afficher
  if (cc < 49.8) return "";

  return cc;
}


function extractNbPhotos(value) {
  if (!value) return 0;

  const s = String(value);

  // ex: "Voir les 5 photos" / "Voir les photos" / "Voir 12 photos"
  const m = s.match(/(\d+)/);
  return m ? parseInt(m[1], 10) : 0;
}

/**
 * Parse matched_generations:
 * Exemples possibles:
 * - "SMCR (Gen2) 2021–2024"
 * - "SMCR (Gen2) 2021→"
 * - "(LC) 2018-2020"
 * - "2021→"
 */
function parseGenerations(value) {
  const s = String(value || "").trim();
  if (!s) return { label: "", yStart: "", yEnd: "" };

  // label = contenu entre parenthèses
  const labelMatch = s.match(/\(([^)]+)\)/);
  const label = labelMatch ? labelMatch[1].trim() : "";

  // Range "2002–2003" ou "2002-2003"
  const rangeMatch = s.match(/(\d{4})\s*[-–]\s*(\d{4})/);
  if (rangeMatch) {
    return { label, yStart: Number(rangeMatch[1]), yEnd: Number(rangeMatch[2]) };
  }

  // Arrow "2018→" => fin = année courante
  const arrowMatch = s.match(/(\d{4})\s*→/);
  if (arrowMatch) {
    return { label, yStart: Number(arrowMatch[1]), yEnd: CURRENT_YEAR };
  }

  // Fallback: une seule année
  const oneYear = s.match(/(\d{4})/);
  if (oneYear) {
    const y = Number(oneYear[1]);
    return { label, yStart: y, yEnd: y };
  }

  return { label: "", yStart: "", yEnd: "" };
}

// ===============================
// MAPPING
// ===============================
function mapField(item) {
  const gen = parseGenerations(item.matched_generations);

  return {
    json: {
      // ===============================
      // IDENTITÉ ANNONCE
      // ===============================
      Nom_annonce: item["text-headline-1-expanded"] || item.annonce_title || "",
      Url_Https: item["absolute href"] || item.annonce_url || "",

      // ✅ Favoris (chiffre uniquement)
      "personnes ont déjà ajouté cette annonce en favori": extractFavoris(item["u-shadow-border-transition"]),

"nombre de photos supplémentaires": extractNbPhotos(item["u-shadow-border-transition (2)"]),

      // ===============================
      // DATE / HEURE
      // ===============================
      "Date de mise en publication": item["text-caption"] || "",
      "Heure de mise en publication": item["text-caption (2)"] || "",

      // ===============================
      // PRIX
      // ===============================
      Prix_affiche: item["flex"] || item["text-headline-1"] || "",

      // ===============================
      // ✅ PHOTOS (3 clés récupérées)
      // ===============================
      Photo_1: item["size-full src"] || "",
      Photo_2: item["size-full src (2)"] || "",
      Photo_3: item["size-full src (3)"] || "",

          // ===============================
    // VEHICULE / VENDEUR (RENOMMÉ)
    // ===============================
    "nom du vendeur pro": item["text-body-1"] || "",

    "année du modèle": item["text-body-1 (4)"] || "",

    "Kilométrage": item["text-body-1 (5)"] || "",

    Mise_en_circulation: item["text-body-1 (6)"] || "",
Cylindree_cc: extractCC(item["text-body-1 (7)"]),

      // ===============================
      // ✅ DESCRIPTION COMPLÈTE
      // ===============================
"Description de l'annonce": item.annonce_description || "",

      // ===============================
      // STATUT / VENDEUR
      // ===============================
      Statut_annonce: item["box-border"] || "",

      // ✅ 3 clés récupérées côté vendeur
      Nom_vendeur: item["text-headline-1 (2)"] || "",
      "nombre d’avis": item["text-body-2"] || "",
      "Dernière activité": item["text-body-2 (2)"] || "",

      // (tu peux garder ces noms internes si tu en as encore besoin ailleurs)
      Paiement_ou_SIREN: item["text-body-2"] || "",
      Infos_vendeur: item["text-body-2 (2)"] || "",

      // ===============================
      // MATCHING
      // ===============================
      matched_marque: item.matched_marque || "",
      matched_modele: item.matched_modele || "",
      matched_generations: item.matched_generations || "",

      generation_label: gen.label || "",
      generation_year_start: gen.yStart || "",
      generation_year_end: gen.yEnd || "",

      matched_score: item.matched_score || "",
      matched_quality: item.matched_quality || "",
      needs_review: item.needs_review ?? false,
    }
  };
}

// ===============================
// RUN
// ===============================
return $input.all().map(i => mapField(i.json));

// =====================================================
// MATCHING v9.3.2 (BRAND KEY FIX) — LBC 2026 KEYS (u_moto_model + cubic_capacity)
// Fix principal:
// - Canonicalise la marque via brandKey() => "CF MOTO" == "CFMOTO"
// - cleanModelFromHref2 retire la marque même si espaces/variantes
// - Toujours return [{json:{...}}] (n8n OK)
// ✅ MAJ KEYS 2026 :
// - Brand: text-body-1 (2) + href marque: text-body-1 href (2) + href modèle: text-body-1 href (3)
// - Title: text-body-1 (8) puis text-headline-1-expanded puis relative/Nom_annonce
// - Desc: annonce_description (ton node matching récent) puis text-body-1 (16) puis text-body-1 (14) puis Description_complete
// - Year: text-body-1 (4) puis text-body-1 (9) puis Annee_du_modele
// - CC: href cubic_capacity via text-body-1 href (5) (le + fiable), sinon champ texte cc: text-body-1 (7)
// - KM: text-body-1 (5) ou "Kilomètrage"
// - Seller: text-headline-1 / text-headline-1 (3) (ex: Jeremy21) + éventuellement "nom du vendeur pro"
// =====================================================

const allItems = $input.all().map(i => i.json);

// -------------------------
// GET / PICK
// -------------------------
const get = (obj, ...keys) => {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
};

const pick = (obj, keys) => {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return "";
};

// -------------------------
// Champs annonces (✅ NEW KEYS 2026 + compat RenameColumns1)
// -------------------------
const getAnnonceTitle = (a) =>
  get(a,
    "text-body-1 (8)",           // ✅ version (très discriminant)
    "text-headline-1-expanded",
    "text-headline-1-expanded (2)",
    "text-headline-1",
    "relative",
    "Nom_annonce",
    "annonce_title"
  );

const getAnnonceDesc = (a) =>
  get(a,
    "annonce_description",       // ✅ ton champ propre du node matching
    "text-body-1 (16)",          // ✅ description complète (exemple)
    "text-body-1 (14)",          // ancien mapping
    "Description_complete",
    "description",
    "annonce_desc"
  );

const getAnnonceUrl = (a) =>
  get(a,
    "absolute href",
    "Url_Https",
    "annonce_url",
    "relative"
  );

// ✅ Brand: maintenant text-body-1 (2)
const getAnnonceBrand = (a) =>
  get(a,
    "text-body-1 (2)",
    "annonce_brand_input",
    "Marque_scrap"
  );

// année brute: (4) puis (9)
const getAnnonceYearRaw1 = (a) => get(a, "text-body-1 (4)", "annonce_year_input_1", "Annee_du_modele");
const getAnnonceYearRaw2 = (a) => get(a, "text-body-1 (9)", "annonce_year_input_2", "Mise_en_circulation");

// ✅ CC via filtre LBC (le + fiable) : href(5)
const getAnnonceCCHref = (a) => get(a, "text-body-1 href (5)");

// ✅ modèle via href(3)
const getAnnonceModelHref = (a) => get(a, "text-body-1 href (3)");

// ✅ href marque (utile pour u_moto_brand)
const getAnnonceBrandHref = (a) => get(a, "text-body-1 href (2)", "text-body-1 href");

// km / seller
const getAnnonceKmField = (a) => get(a, "text-body-1 (5)", "Kilomètrage", "Nombre_de_kilometres", "kilometrage");
const getAnnonceSeller  = (a) => get(a, "text-headline-1", "text-headline-1 (3)", "Nom_vendeur", "nom du vendeur pro", "seller_name");
const getAnnoncePayment = (a) => get(a, "Paiement_ou_SIREN");

// -------------------------
// Champs modèles (référentiel)
// -------------------------
const getModeleField = (m) => pick(m, ["Modèle","Modele","modele","Model","MODELE","Modèle "]) || "";
const getMarqueField = (m) => pick(m, ["Marque","marque","MARQUE","Brand","brand"]) || "";
const getYearStartField = (m) => pick(m, ["Année début","Annee debut","Année début ","Year start","yearStart"]) || "";
const getYearEndField   = (m) => pick(m, ["Année fin","Annee fin","Année fin ","Year end","yearEnd"]) || "";

// -------------------------
// Normalisation / Tokenize
// -------------------------
const STOP = new Set([
  "moto","motos","scooter","roadster","trail","enduro","cross",
  "vend","vente","vends","urgent","etat","tres","super","parfait","excellent",
  "paiement","securise","option","full","abs","a2","ct","ok",
  "km","kms","kilometrage","kilometres","boite","vitesse","manuelle","automatique",
  "prix","euro","eur","garantie","factures","entretien","revision","controle"
]);

function normalize(text) {
  if (!text) return "";
  let s = String(text)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();

  s = s.replace(/_/g, " ");
  s = s.replace(/[/|]/g, " ");
  s = s.replace(/[^a-z0-9]+/g, " ");
  s = s.replace(/\s+/g, " ").trim();

  s = s.replace(/\b(mt)\s*0?(\d{2})\b/g, "$1$2");
  s = s.replace(/\b(fz)\s*(\d)\b/g, "$1$2");
  s = s.replace(/\b(gs)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(dl)\s*(\d{3,4})\b/g, "$1$2");
  s = s.replace(/\b(v\s*strom)\b/g, "vstrom");
  s = s.replace(/\b(v[-\s]?strom)\b/g, "vstrom");
  s = s.replace(/\b(dr)\s*z\b/g, "drz");

  return s;
}

// ✅ clé marque canonique : supprime espaces (CF MOTO == CFMOTO)
function brandKey(brand) {
  return normalize(brand).replace(/\s+/g, "");
}

function splitAlphaNum(tok) {
  const parts = String(tok).match(/[a-z]+|\d+/g);
  return parts && parts.length > 1 ? parts : [];
}

function tokenizeAny(text) {
  const n = normalize(text);
  if (!n) return [];
  const raw = n.split(" ").filter(Boolean);
  const out = [];

  for (const t0 of raw) {
    out.push(t0);
    const parts = splitAlphaNum(t0);
    if (parts.length) out.push(...parts);
  }

  return out.filter(t => {
    if (!t) return false;
    if (STOP.has(t)) return false;
    if (/^\d+$/.test(t)) return true;
    return t.length >= 2;
  });
}

function tokenizeModel(text) {
  const n = normalize(text);
  if (!n) return [];
  const raw = n.split(" ").filter(Boolean);
  const out = [];
  for (const t0 of raw) {
    const parts = splitAlphaNum(t0);
    if (parts.length) out.push(...parts);
    else out.push(t0);
  }
  return out.filter(t => {
    if (!t) return false;
    if (STOP.has(t)) return false;
    if (/^\d+$/.test(t)) return true;
    return t.length >= 2;
  });
}

const tokensAlphaOnly = (tokens) => tokens.filter(t => /[a-z]/.test(t));

// -------------------------
// Parsing année
// -------------------------
function parseYearMonth(s) {
  const str = String(s || "").trim();
  if (!str) return { year: 0, month: 0 };

  const mmyyyy = str.match(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/);
  if (mmyyyy) return { month: parseInt(mmyyyy[1], 10), year: parseInt(mmyyyy[2], 10) };

  const yyyy = str.match(/\b(19|20)\d{2}\b/);
  if (yyyy) return { month: 0, year: parseInt(yyyy[0], 10) };

  return { year: 0, month: 0 };
}

function pickAnnonceYear(a, adText) {
  const d2 = parseYearMonth(getAnnonceYearRaw2(a));
  if (d2.year) return d2.year;

  const d1 = parseYearMonth(getAnnonceYearRaw1(a));
  if (d1.year) return d1.year;

  const m = String(adText || "").match(/\b(19|20)\d{2}\b/);
  if (m) return parseInt(m[0], 10);

  return 0;
}

// -------------------------
// CC (✅ NEW KEYS 2026)
// -------------------------
function ccFromHref(href) {
  const s = String(href || "");
  const m = s.match(/cubic_capacity:(\d{2,4})/i);
  return m ? parseInt(m[1], 10) : 0;
}

function extractCCFromText(text) {
  const raw = String(text || "");
  if (!raw.trim()) return 0;

  const noKm = raw.replace(/\b(\d{1,6})\s*km\b/gi, " ");
  const s = normalize(noKm);

  let m = s.match(/\b(\d{2,4})\s*(cc|cm3|cm 3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  m = s.match(/\b(\d{2,4})(cc|cm3|ccm)\b/);
  if (m) return parseInt(m[1], 10);

  return 0;
}

function extractNumbers(text) {
  const raw = String(text || "")
    .replace(/\b(\d{1,6})\s*km\b/gi, " ")
    .replace(/\b(0?[1-9]|1[0-2])\s*\/\s*((19|20)\d{2})\b/g, " ");
  const s = normalize(raw);
  return (s.match(/\b\d{3,4}\b/g) || []).map(n => parseInt(n, 10));
}

// ⚠️ On garde ton infer, MAIS en dernier recours (v9.3.2)
function inferCCFromNumbers(adText, annonceYear) {
  const nums = extractNumbers(adText);
  const candidates = nums.filter(n => n >= 80 && n <= 2500 && (!annonceYear || n !== annonceYear));
  if (!candidates.length) return 0;
  return Math.max(...candidates);
}

function getAnnonceCC(a, adText, annonceYear) {
  // 1) href cubic_capacity
  const ccH = ccFromHref(getAnnonceCCHref(a));
  if (ccH) return ccH;

  // 2) champ cc textuel dédié (✅ text-body-1 (7) = "1050")
  const ccTxt = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc");
  const ccField = extractCCFromText(ccTxt);
  if (ccField) return ccField;

  // 3) texte global
  const ccT = extractCCFromText(adText);
  if (ccT) return ccT;

  // 4) dernier recours
  const ccN = inferCCFromNumbers(adText, annonceYear || 0);
  if (ccN) return ccN;

  return 0;
}

// -------------------------
// u_moto_brand / u_moto_model depuis href
// -------------------------
function decodePlus(s) { return String(s || "").replace(/\+/g, " "); }

function extractBrandFromHref(href) {
  const h = String(href || "");
  if (!h) return "";
  const m = h.match(/u_moto_brand:([^+&]+)/i);
  if (!m) return "";
  try { return decodeURIComponent(decodePlus(m[1])); }
  catch (e) { return decodePlus(m[1]); }
}

function extractModelFromHref2(href2) {
  const h = String(href2 || "");
  if (!h) return "";
  const m = h.match(/u_moto_model:([^+&]+)/i);
  if (!m) return "";
  try { return decodeURIComponent(decodePlus(m[1])); }
  catch (e) { return decodePlus(m[1]); }
}

function prettyBrand(raw) {
  const s = String(raw || "").trim();
  if (!s) return "";
  if (s === s.toUpperCase()) return s;
  return s
    .toLowerCase()
    .split(/\s+/)
    .map(w => w.charAt(0).toUpperCase() + w.slice(1))
    .join(" ");
}

function resolveBrandForOutput(a, hrefBrand) {
  const rawHref = extractBrandFromHref(hrefBrand);
  const rawField = getAnnonceBrand(a);
  return prettyBrand(rawHref || rawField);
}

function cleanModelFromHref2(modelStr, brandRawOrNorm) {
  if (!modelStr) return "";
  const original = String(modelStr).replace(/_/g, " ").trim();
  const n = normalize(original);

  if (n === "autre" || n.endsWith(" autre") || n.includes(" autre ")) return "";

  if (brandRawOrNorm) {
    const bk = brandKey(brandRawOrNorm);
    const origTokens = original.split(/\s+/);

    for (let take = Math.min(4, origTokens.length); take >= 1; take--) {
      const head = origTokens.slice(0, take).join(" ");
      if (brandKey(head) === bk) {
        return origTokens.slice(take).join(" ").trim();
      }
    }
  }

  return original;
}

function isHref2Autre(href2) {
  const raw = extractModelFromHref2(href2);
  const n = normalize(raw);
  return !raw || n === "autre" || n.endsWith(" autre") || n.includes(" autre ");
}

function extractModelHintFromTitle(title, brandRawOrNorm) {
  const t = String(title || "").trim();
  if (!t) return "";

  let s = t;

  if (brandRawOrNorm) {
    const bk = brandKey(brandRawOrNorm);
    const toks = s.split(/\s+/);
    for (let take = Math.min(4, toks.length); take >= 1; take--) {
      const head = toks.slice(0, take).join(" ");
      if (brandKey(head) === bk) {
        s = toks.slice(take).join(" ").trim();
        break;
      }
    }
  }

  s = s.replace(/\b(neuf|neuve|garantie|disponible|stock|espace|motos|moto|ans|km)\b/gi, " ");

  const toks = tokenizeModel(s);
  const keep = [];
  for (const t0 of toks) {
    if (/^(19|20)\d{2}$/.test(t0)) continue;
    keep.push(t0);
    if (keep.length >= 4) break;
  }
  return keep.length ? keep.join(" ") : "";
}

// -------------------------
// Similarités
// -------------------------
function jaccard(aTokens, bTokens) {
  if (!aTokens.length || !bTokens.length) return 0;
  const A = new Set(aTokens);
  const B = new Set(bTokens);
  let inter = 0;
  for (const x of A) if (B.has(x)) inter++;
  const union = A.size + B.size - inter;
  return union ? inter / union : 0;
}

function coverageSet(adSet, modelTokens) {
  if (!modelTokens.length) return 0;
  let hit = 0;
  for (const t of modelTokens) if (adSet.has(t)) hit++;
  return hit / modelTokens.length;
}

function getModelDominantTokens(modelRaw) {
  const n = normalize(modelRaw);
  const nums = n.match(/\b\d{3,4}\b/g) || [];
  if (nums.length) return nums.map(Number);
  const toks = tokenizeAny(modelRaw);
  return toks.filter(t => /\d/.test(t) || t.length >= 4);
}

function modelVariants(modelRaw) {
  const cleaned = String(modelRaw || "").replace(/[|]/g, "/");
  const parts = cleaned.split("/").map(p => p.trim()).filter(Boolean);
  return Array.from(new Set(parts.map(p => normalize(p)).filter(Boolean)));
}

// -------------------------
// Seller flags
// -------------------------
function parseKmFromField(s) {
  const str = String(s || "");
  const m = str.replace(/\u202f/g, " ").replace(/\s/g, "").match(/(\d{1,6})km/i);
  return m ? parseInt(m[1], 10) : 0;
}

function detectSellerFlags(a, adText) {
  const sellerName = String(getAnnonceSeller(a) || "").trim();
  const payment = String(getAnnoncePayment(a) || "").trim();
  const km = parseKmFromField(getAnnonceKmField(a));

  const blob = `${sellerName} ${payment} ${adText}`;

  const proSignals = /\b(siret|siren|tva|rcs|immatricul|professionnel|vendeur\s*pro|concession\b|concessionnaire|garage|showroom|reprise|financement|leasing|cr[eé]dit)\b/i;
  const proFalseContext = /\b(entretenu(e)?|revision|r[eé]vis[eé])\s+(chez|en)\s+(le|la)\s+(concessionnaire|garage)\b/i;
  const companySignals = /\b(sarl|sas|eurl|auto-entrepreneur|entreprise|moto(s)?\s*occ|occasion(s)?|motors|autos?)\b/i;

  let isPro = false;
  if (sellerName) isPro = companySignals.test(sellerName) || /\b(siret|siren)\b/i.test(blob);
  if (!isPro && proSignals.test(blob) && !proFalseContext.test(blob)) isPro = true;

  const newTrue = /\b(0\s*km|0\s*kms|jamais\s+immatricul[eé]e?|moto\s+neuve|vehicule\s+neuf|neuf\s+jamais\s+roul[eé])\b/i;
  const newFalseParts = /\b(batterie|pneu(x)?|plaquette(s)?|kit\s*chaine|chaine|disque(s)?|huile|vidange|filtre)\s+neuf(s|ve|ves)?\b/i;

  let isNew = newTrue.test(adText);
  if (!isNew && /\b(neuf|neuve)\b/i.test(adText) && !newFalseParts.test(adText)) isNew = false;

  return { sellerName, km, isPro, isNew };
}

// -------------------------
// Out of scope (ne SKIP pas si modelHint valide)
// -------------------------
function isNonMotoListing(a, adTextUsed, modelHintClean) {
  const typeField = normalize(get(a, "text-body-1 (10)", "Type_vehicule", "type", "vehicle_type"));

  if (modelHintClean && String(modelHintClean).trim() !== "") return { skip: false, reason: "" };

  if (typeField && typeField !== "moto") return { skip: true, reason: `type_not_moto:${typeField}` };

  const title = normalize(getAnnonceTitle(a));
  const desc  = normalize(getAnnonceDesc(a));
  const blob  = `${title} ${desc} ${normalize(adTextUsed)}`;

  const reNonMoto = /\b(trottinette|edpm|nami|dualtron|kaabo|weped|speedway|monoroue|gyropode|hoverboard)\b/i;
  const reParts   = /\b(piece|pieces|accessoire|accessoires|casque|gants|blouson|bottes|pneu|pneus|jante|echappement|ligne|silencieux)\b/i;

  if (reNonMoto.test(blob)) return { skip: true, reason: "non_moto_vehicle" };
  if (reParts.test(blob))   return { skip: true, reason: "parts_or_accessories" };

  return { skip: false, reason: "" };
}

// -------------------------
// Split modèles / annonces
// -------------------------
const modeles = [];
const annonces = [];

for (const item of allItems) {
  const isModele = !!getMarqueField(item) && !!getModeleField(item) && (get(item, "Cylindrée (cc)", "Type (M/S/E)", "Type(M/S/E)", "Type (M\\/S\\/E)") !== "");
  const isAnnonce = get(item, "text-body-1 (8)", "text-headline-1-expanded", "relative", "absolute href", "Url_Https", "annonce_url") !== "";
  if (isModele) modeles.push(item);
  else if (isAnnonce) annonces.push(item);
}

if (!modeles.length) {
  return annonces.map(a => ({ json: { ...a, matching_engine: "NO_MODELS_INPUT", matched_score: 0, needs_review: true } }));
}

// -------------------------
// Index marques (sur brandKey)
// -------------------------
const brandIndex = new Map();

for (const m of modeles) {
  const brandRaw = getMarqueField(m);
  const modelRaw = getModeleField(m);

  const bKey = brandKey(brandRaw);
  if (!bKey) continue;

  const variants = modelVariants(modelRaw);
  if (!variants.length) continue;

  const ys = parseInt(getYearStartField(m) || 0, 10) || 0;
  let ye = getYearEndField(m);
  ye = (ye === null || ye === undefined || ye === "") ? 9999 : (parseInt(ye, 10) || 9999);

  const cc = Math.round(Number(get(m, "Cylindrée (cc)") || 0)) || 0;

  const variantAlphaTokens = variants
    .map(v => tokensAlphaOnly(tokenizeAny(v)))
    .filter(t => t.length);

  if (!variantAlphaTokens.length) continue;

  const doms = getModelDominantTokens(modelRaw);
  const modelNoSpace = normalize(modelRaw).replace(/\s+/g, "");

  const prepared = {
    raw: m,
    brandRaw,
    bKey,
    ys,
    ye,
    cc,
    variants,
    variantAlphaTokens,
    combinedTok: tokenizeAny(`${brandRaw} ${modelRaw}`),
    dominants: doms,
    modelNoSpace
  };

  if (!brandIndex.has(bKey)) brandIndex.set(bKey, []);
  brandIndex.get(bKey).push(prepared);
}

const knownBrandKeys = Array.from(brandIndex.keys()).sort((a, b) => b.length - a.length);

// -------------------------
// Seuils (-10%)
// -------------------------
const MIN_COV_ALPHA = 0.54;
const MIN_ACCEPT    = 0.648;
const CC_BLOCK_DIFF = 315;
const CC_PENALTY    = 0.072;

function computeScore(adTok, adSet, p) {
  let bestCov = 0;
  for (const vat of p.variantAlphaTokens) {
    const cov = coverageSet(adSet, vat);
    if (cov > bestCov) bestCov = cov;
  }
  const jac = jaccard(adTok, p.combinedTok);
  const score = (0.88 * bestCov) + (0.12 * jac);
  return { score, bestCov, jac };
}

// -------------------------
// MATCHING
// -------------------------
const results = [];

for (const a of annonces) {
  const title = getAnnonceTitle(a);
  const desc  = getAnnonceDesc(a);
  const url   = getAnnonceUrl(a);

  const hrefModel = getAnnonceModelHref(a) || ""; // ✅ href(3)
  const hrefCC    = getAnnonceCCHref(a) || "";    // ✅ href(5)

  const hrefBrand = getAnnonceBrandHref(a) || ""; // ✅ href(2) ou href marque fallback
  const brandOut  = resolveBrandForOutput(a, hrefBrand);

  const brandFromHrefRaw = extractBrandFromHref(hrefBrand);
  const brandFromHrefKey = brandKey(brandFromHrefRaw);

  const brandFromFieldRaw = getAnnonceBrand(a);
  const brandFromFieldKey = brandKey(brandFromFieldRaw);

  const ccTxtField = get(a, "text-body-1 (7)", "vehicule_cc_txt", "CC", "cc"); // ✅

  const adTextBase = `${title} ${desc} ${ccTxtField} ${hrefCC}`.trim();
  const adNormBase = normalize(adTextBase);

  // marque: priorité href -> champ -> détection dans texte
  let brandAnnonceKey = brandFromHrefKey || brandFromFieldKey;

  if (!brandAnnonceKey) {
    const blobKey = brandKey(adNormBase);
    for (const bk of knownBrandKeys) {
      if (blobKey.includes(bk)) { brandAnnonceKey = bk; break; }
    }
  }

  // modèle hint depuis hrefModel
  const rawModelFromHref2 = extractModelFromHref2(hrefModel);

  let modelHint = cleanModelFromHref2(
    rawModelFromHref2,
    brandFromHrefRaw || brandFromFieldRaw
  );

  const titleHint = extractModelHintFromTitle(
    title,
    brandFromHrefRaw || brandFromFieldRaw
  );

  const hintHasDigits = (s) => /\b\d{2,4}\b/.test(normalize(s));
  const hintTokenCount = (s) => tokenizeModel(s).length;

  const modelHintGeneric =
    !modelHint ||
    (!hintHasDigits(modelHint) && hintTokenCount(modelHint) <= 1);

  if (modelHintGeneric && titleHint) {
    const titleBetter = hintHasDigits(titleHint) || hintTokenCount(titleHint) >= 2;
    if (titleBetter) modelHint = titleHint;
  }

  if (!modelHint && isHref2Autre(hrefModel)) {
    modelHint = titleHint;
  }

  const adTextUsed = modelHint ? `${adTextBase} ${modelHint}`.trim() : adTextBase;

  const annonceYear = pickAnnonceYear(a, adTextUsed);
  const annonceCC   = getAnnonceCC(a, adTextUsed, annonceYear);
  const sellerFlags = detectSellerFlags(a, adTextUsed);

  const nonMoto = isNonMotoListing(a, adTextUsed, modelHint);
  if (nonMoto.skip) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",
        cc_source_href: ccFromHref(hrefCC) || "",
        seller_is_pro: sellerFlags.isPro,
        seller_is_new: sellerFlags.isNew,

        matched_ok: false,
        matched_quality: "no_match",
        matched_marque: brandOut || "",
        matched_modele: modelHint || "",
        matched_generations: "",
        matched_coloris: "",
        matched_annee_debut: "",
        matched_annee_fin: "",
        matched_cylindree: "",
        matched_score: 0,

        matching_engine: "SKIP_OUT_OF_SCOPE",
        needs_review: false,
        reason_no_match: nonMoto.reason,
        _match_debug: {
          detectedBrand: normalize(brandFromHrefRaw || brandFromFieldRaw) || null,
          brandFromHref: normalize(brandFromHrefRaw) || null,
          hrefBrand: hrefBrand || null,
          hrefModel,
          modelHint
        }
      }
    });
    continue;
  }

  if (!brandAnnonceKey || !brandIndex.has(brandAnnonceKey)) {
    results.push({
      json: {
        ...a,
        annonce_title: title,
        annonce_url: url,
        annonce_year_resolved: annonceYear || "",
        annonce_cc_resolved: annonceCC || "",
        cc_source_href: ccFromHref(hrefCC) || "",
        seller_is_pro: sellerFlags.isPro,
        seller_is_new: sellerFlags.isNew,

        matched_ok: false,
        matched_quality: "no_match",
        matched_marque: "",
        matched_modele: modelHint || "",
        matched_generations: "",
        matched_coloris: "",
        matched_annee_debut: "",
        matched_annee_fin: "",
        matched_cylindree: "",
        matched_score: 0,

        matching_engine: "NO_MATCH",
        needs_review: true,
        reason_no_match: "brand_not_in_ref",
        _match_debug: {
          detectedBrand: normalize(brandFromHrefRaw || brandFromFieldRaw) || null,
          brandFromHref: normalize(brandFromHrefRaw) || null,
          hrefBrand: hrefBrand || null,
          brandAnnonceKey,
          hrefModel,
          modelHint,
          adTextPreview: adTextUsed.slice(0, 250),
        }
      }
    });
    continue;
  }

  const adTok = tokenizeAny(adTextUsed);
  const adSet = new Set(adTok);
  const adNumbers = extractNumbers(adTextUsed);

  let baseCandidates = brandIndex.get(brandAnnonceKey) || [];

  if (annonceCC) {
    const filtered = baseCandidates.filter(p => !p.cc || Math.abs(p.cc - annonceCC) <= CC_BLOCK_DIFF);
    if (filtered.length >= 3) baseCandidates = filtered;
  }

  const passes = [{ useYear: true }, { useYear: false }];

  let bestPrepared = null;
  let bestScore = 0;
  let bestCov = 0;
  let bestJac = 0;
  let usedYearFilter = false;
  let ccPenaltyApplied = false;
  let dominantGateRejectedCount = 0;

  for (const pass of passes) {
    let foundInPass = false;

    for (const p of baseCandidates) {
      if (pass.useYear && annonceYear) {
        if (annonceYear < p.ys || annonceYear > p.ye) continue;
      }

      // Dominant gate assoupli si hint/hrefModel
      const hasHint = !!(modelHint && String(modelHint).trim());
      const hasHref2Model = !!(rawModelFromHref2 && String(rawModelFromHref2).trim());
      const relaxDominantGate = hasHint || hasHref2Model;

      let hintBypass = false;
      if (hasHint) {
        const modelNoSpace = p.modelNoSpace || "";
        const hintNoSpace = normalize(modelHint).replace(/\s+/g, "");
        if (modelNoSpace && hintNoSpace.includes(modelNoSpace)) hintBypass = true;

        if (!hintBypass && p.dominants && p.dominants.length) {
          const hintTok = new Set(tokenizeAny(modelHint));
          for (const d of p.dominants) {
            if (typeof d === "number") {
              if (adNumbers.includes(d)) { hintBypass = true; break; }
            } else {
              if (hintTok.has(String(d))) { hintBypass = true; break; }
            }
          }
        }
      }

      if (!relaxDominantGate && !hintBypass && p.dominants && p.dominants.length) {
        let dominantHit = false;
        for (const d of p.dominants) {
          if (typeof d === "number") {
            if (adNumbers.includes(d)) { dominantHit = true; break; }
          } else {
            if (adSet.has(String(d))) { dominantHit = true; break; }
          }
        }
        if (!dominantHit) { dominantGateRejectedCount++; continue; }
      }

      const { score, bestCov: covA, jac } = computeScore(adTok, adSet, p);
      if (covA < MIN_COV_ALPHA) continue;

      let finalScore = score;

      if (annonceCC && p.cc) {
        const diff = Math.abs(p.cc - annonceCC);
        if (diff >= CC_BLOCK_DIFF) continue;
        if (diff > 50) { finalScore = Math.max(0, finalScore - CC_PENALTY); ccPenaltyApplied = true; }
      }

      if (finalScore > bestScore) {
        bestScore = finalScore;
        bestPrepared = p;
        bestCov = covA;
        bestJac = jac;
        usedYearFilter = pass.useYear && !!annonceYear;
        foundInPass = true;
      }
    }

    if (pass.useYear && foundInPass) break;
  }

  const accept = !!bestPrepared && bestScore >= MIN_ACCEPT;
  const best = accept ? bestPrepared.raw : null;

  results.push({
    json: {
      ...a,
      annonce_title: title,
      annonce_url: url,
      annonce_year_resolved: annonceYear || "",
      used_year_filter: usedYearFilter,
      annonce_cc_resolved: annonceCC || "",
      cc_source_href: ccFromHref(hrefCC) || "",
      seller_is_pro: sellerFlags.isPro,
      seller_is_new: sellerFlags.isNew,

      matched_ok: accept,
      matched_quality: accept ? "auto_match" : "no_match",

      matched_marque: accept ? (getMarqueField(best) || "") : (brandOut || ""),
      matched_modele: accept ? (getModeleField(best) || "") : (modelHint || ""),
      matched_generations: accept ? (get(best, "Spéc/Génération", "Spec/Generation") || "") : "",
      matched_coloris: accept ? (get(best, "Coloris commercial") || "") : "",
      matched_annee_debut: accept ? (get(best, "Année début") || getYearStartField(best) || "") : "",
      matched_annee_fin: accept ? (get(best, "Année fin") || getYearEndField(best) || "") : "",
      matched_cylindree: accept ? (get(best, "Cylindrée (cc)") || "") : "",

      matched_score: accept ? Number(bestScore.toFixed(3)) : 0,
      matched_jaccard: Number(bestJac.toFixed(3)),
      matching_engine: accept ? "AUTO_V9_3_2_BRANDKEY_LBC2026" : "NO_MATCH",
      needs_review: !accept,
      reason_no_match: accept ? "" : "below_threshold_or_no_candidate_after_gates",

      _match_debug: {
        detectedBrand: normalize(brandFromHrefRaw || brandFromFieldRaw) || null,
        brandFromHref: normalize(brandFromHrefRaw) || null,
        hrefBrand: hrefBrand || null,
        brandAnnonceKey,
        adTextPreview: adTextUsed.slice(0, 250),
        hrefModel,
        modelHint,
        adNumbers,
        dominantGateRejectedCount,
        covAlphaBest: Number(bestCov.toFixed(3)),
        jacBest: Number(bestJac.toFixed(3)),
        minCovAlpha: MIN_COV_ALPHA,
        minAccept: MIN_ACCEPT,
        ccPenaltyApplied,
        ccResolved: annonceCC || 0,
        adTokensCount: adTok.length,
      }
    }
  });
}

return results;
